import { supabase } from './supabase';

const TABLE_NAME = 'spray_cycles';

export const sprayCyclesService = {
    async getAll() {
        const { data, error } = await supabase
            .from(TABLE_NAME)
            .select('*')
            .order('date', { ascending: false });
        if (error) throw error;
        return data;
    },
    async create(payload) {
        const { data, error } = await supabase.from(TABLE_NAME).insert([payload]).select();
        if (error) throw error;
        return data[0];
    },
    async update(id, payload) {
        const { data, error } = await supabase.from(TABLE_NAME).update(payload).eq('id', id).select();
        if (error) throw error;
        return data[0];
    },
    async delete(id) {
        const { error } = await supabase.from(TABLE_NAME).delete().eq('id', id);
        if (error) throw error;
        return true;
    }
};