import React, { useMemo, useState, useEffect } from 'react';
import './Chemicals.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';
import { chemicalsService } from '../../services/chemicals';

function Chemicals() {
  const [purchases, setPurchases] = useState([]);
  const [loading, setLoading] = useState(true);
  const [mode, setMode] = useState('list');
  const [editingPurchase, setEditingPurchase] = useState(null);
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 5;
  const [confirmState, setConfirmState] = useState({ open: false, target: null });
  const [notification, setNotification] = useState(null);

  const [searchTerm, setSearchTerm] = useState('');
  const [dateRange, setDateRange] = useState('all');
  const [customDate, setCustomDate] = useState('');
  const [showFilters, setShowFilters] = useState(false);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const result = await chemicalsService.getAll();
    if (result.success) {
      setPurchases(result.data);
    } else {
      showNotification('خطأ في جلب البيانات: ' + result.error);
    }
    setLoading(false);
  };

  const showNotification = (msg) => {
    setNotification(msg);
    setTimeout(() => setNotification(null), 3000);
  };

  const handleEditPurchase = (purchase) => {
    setEditingPurchase({ ...purchase });
    setMode('form');
  };

  // --- منطق الفلترة الاحترافي ---
  const filteredPurchases = useMemo(() => {
    // 1. الحصول على تاريخ اليوم "صافي" بدون ساعات
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    return purchases.filter((p) => {
      // 2. تحويل تاريخ الشراء لكائن Date وضبط ساعاته للصفر
      const pDate = new Date(p.purchase_date);
      pDate.setHours(0, 0, 0, 0);

      // 3. فلترة البحث بالاسم
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());

      // 4. منطق النطاق الزمني
      let matchesRange = true;

      if (dateRange === 'week') {
        const weekAgo = new Date(today);
        weekAgo.setDate(today.getDate() - 7);
        // من 7 أيام مضت وحتى نهاية اليوم
        matchesRange = pDate >= weekAgo && pDate <= today;
      }
      else if (dateRange === 'month') {
        const monthAgo = new Date(today);
        monthAgo.setMonth(today.getMonth() - 1);
        matchesRange = pDate >= monthAgo && pDate <= today;
      }
      else if (dateRange === 'year') {
        const yearAgo = new Date(today);
        yearAgo.setFullYear(today.getFullYear() - 1);
        matchesRange = pDate >= yearAgo && pDate <= today;
      }
      else if (dateRange === 'custom' && customDate) {
        // تحويل الـ customDate (string) لكائن Date للمقارنة بدقة
        const targetDate = new Date(customDate);
        targetDate.setHours(0, 0, 0, 0);
        matchesRange = pDate.getTime() === targetDate.getTime();
      }

      return matchesSearch && matchesRange;
    });
  }, [purchases, searchTerm, dateRange, customDate]);

  const totalPages = Math.max(1, Math.ceil(filteredPurchases.length / pageSize));

  // تصفير الصفحة عند البحث
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, dateRange, customDate]);

  const pagedPurchases = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return filteredPurchases.slice(start, start + pageSize);
  }, [filteredPurchases, currentPage]);

  const handleConfirmDelete = async () => {
    const target = confirmState.target;
    if (!target) return;
    const result = await chemicalsService.delete(target.id);
    if (result.success) {
      setPurchases(purchases.filter((p) => p.id !== target.id));
      showNotification('تم الحذف بنجاح');
    }
    setConfirmState({ open: false, target: null });
  };

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const payload = {
      name: editingPurchase.name,
      purchase_date: editingPurchase.purchase_date,
      quantity: parseFloat(editingPurchase.quantity),
      unit: editingPurchase.unit,
      cost: parseFloat(editingPurchase.cost)
    };

    if (!editingPurchase.id) {
      const result = await chemicalsService.add(payload);
      if (result.success) {
        setPurchases([result.data, ...purchases]);
        setMode('list');
        showNotification('تمت الإضافة بنجاح');
      } else {
        showNotification('خطأ في الإضافة: ' + result.error);
      }
    } else {
      const result = await chemicalsService.update(editingPurchase.id, payload);
      if (result.success) {
        setPurchases(purchases.map(p => p.id === editingPurchase.id ? result.data : p));
        setMode('list');
        showNotification('تم التعديل بنجاح');
      } else {
        showNotification('خطأ في التعديل: ' + result.error);
      }
    }
    setLoading(false);
  };

  if (loading && purchases.length === 0) return <div className="loading">جاري التحميل...</div>;

  return (
    <div className="chemicals-page">
      {notification && <div className="notification-banner">{notification}</div>}

      <div className="chemicals-header-row">
        <div>
          <h1 className="chemicals-title">سجل الكيماويات</h1>
          <p className="chemicals-subtitle">متابعة عمليات الشراء والفلترة الذكية للمخزون.</p>
        </div>

      </div>

      {mode === 'form' && editingPurchase && (
        <div className="chem-card chem-form-card">
          <h2 className="form-title">{editingPurchase.id ? 'تعديل السجل' : 'إضافة سجل شراء'}</h2>
          <form className="chem-form" onSubmit={handleFormSubmit}>
            <div className="form-row two-cols">
              <div>
                <label>اسم المادة</label>
                <input type="text" value={editingPurchase.name} onChange={(e) => setEditingPurchase({ ...editingPurchase, name: e.target.value })} required />
              </div>
              <div>
                <label>تاريخ الشراء</label>
                <input type="date" value={editingPurchase.purchase_date} onChange={(e) => setEditingPurchase({ ...editingPurchase, purchase_date: e.target.value })} required />
              </div>
            </div>
            <div className="form-row two-cols">
              <div>
                <label>الكمية</label>
                <input type="number" step="0.01" value={editingPurchase.quantity} onChange={(e) => setEditingPurchase({ ...editingPurchase, quantity: e.target.value })} required />
              </div>
              <div>
                <label>الوحدة</label>
                <input type="text" value={editingPurchase.unit} onChange={(e) => setEditingPurchase({ ...editingPurchase, unit: e.target.value })} placeholder="لتر / كجم" required />
              </div>
            </div>
            <div className="form-row">
              <div>
                <label>التكلفة الإجمالية (ج.م)</label>
                <input type="number" value={editingPurchase.cost} onChange={(e) => setEditingPurchase({ ...editingPurchase, cost: e.target.value })} required />
              </div>
            </div>
            <div className="form-actions">
              <button type="button" className="btn-secondary" onClick={() => setMode('list')}>إلغاء</button>
              <button type="submit" className="btn-primary" disabled={loading}>حفظ</button>
            </div>
          </form>
        </div>
      )}

      <div className="chemicals-stats-row">
        <div className="chem-card stat-card">
          <span className="stat-label">إجمالي التكاليف المعروضة</span>
          <span className="stat-value">{(filteredPurchases.reduce((s, p) => s + (Number(p.cost) || 0), 0)).toLocaleString('ar-EG')} ج.م</span>
        </div>
        <div className="chem-card stat-card">
          <span className="stat-label">عدد العمليات</span>
          <span className="stat-value">{filteredPurchases.length} عملية</span>
        </div>
      </div>

      <div className="chemicals-table-card chem-card">
        <div className="chemicals-table-header">
          <div className="header-main-actions">
            <button className="btn-primary" onClick={() => {
              setEditingPurchase({ name: '', purchase_date: new Date().toISOString().slice(0, 10), quantity: '', unit: '', cost: 0 });
              setMode('form');
            }}>
              <span className="material-symbols-outlined">add</span>
              تسجيل شراء
            </button>
            <div className="search-box">
              <span className="material-symbols-outlined">search</span>
              <input
                type="text"
                placeholder="ابحث باسم المادة..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>
          <div className="chem-table-actions">
            <button className={`btn-chip ${showFilters ? 'active' : ''}`} onClick={() => setShowFilters(!showFilters)}>
              <span className="material-symbols-outlined">filter_alt</span>
              خيارات الفلترة
            </button>
          </div>
        </div>

        {showFilters && (
          <div className="filter-drawer">
            <div className="filter-group">
              <label>الفترة الزمنية:</label>
              <select value={dateRange} onChange={(e) => setDateRange(e.target.value)} className="filter-select">
                <option value="all">الكل (كافة الأوقات)</option>
                <option value="week">آخر 7 أيام</option>
                <option value="month">آخر 30 يوم</option>
                <option value="year">آخر سنة</option>
                <option value="custom">تاريخ محدد...</option>
              </select>
              {dateRange === 'custom' && (
                <input type="date" value={customDate} onChange={(e) => setCustomDate(e.target.value)} className="filter-date-input" />
              )}
              <button className="clear-btn" onClick={() => { setDateRange('all'); setCustomDate(''); setSearchTerm(''); }}>إعادة ضبط</button>
            </div>
          </div>
        )}

        <div className="chemicals-table-wrapper">
          <table className="chemicals-table">
            <thead>
              <tr>
                <th>التاريخ</th>
                <th>المادة</th>
                <th>الكمية</th>
                <th>الوحدة</th>
                <th>التكلفة</th>
                <th>الإجراءات</th>
              </tr>
            </thead>
            <tbody>
              {pagedPurchases.length > 0 ? pagedPurchases.map((p) => (
                <tr key={p.id}>
                  <td>{new Date(p.purchase_date).toLocaleDateString('ar-EG')}</td>
                  <td>{p.name}</td>
                  <td>{p.quantity}</td>
                  <td>{p.unit}</td>
                  <td>{(Number(p.cost)).toLocaleString('ar-EG')} ج.م</td>
                  <td>
                    <div className="chem-row-actions">
                      <button className="icon-btn danger" onClick={() => setConfirmState({ open: true, target: p })}><span className="material-symbols-outlined">delete</span></button>
                      <button className="icon-btn" onClick={() => handleEditPurchase(p)}><span className="material-symbols-outlined">edit</span></button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr><td colSpan="6" style={{ textAlign: 'center', padding: '30px' }}>لا توجد سجلات مطابقة</td></tr>
              )}
            </tbody>
          </table>
        </div>

        <div className="chemicals-table-footer">
          <span>عرض {pagedPurchases.length} من أصل {filteredPurchases.length} عملية شراء</span>
          <div className="pagination">
            <button
              className={`page-btn ${currentPage === 1 ? 'disabled' : ''}`}
              onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
              disabled={currentPage === 1}
            >
              <span className="material-symbols-outlined">chevron_right</span>
            </button>

            {Array.from({ length: totalPages }).map((_, i) => {
              const page = i + 1;
              return (
                <button
                  key={page}
                  className={`page-btn ${currentPage === page ? 'active' : ''}`}
                  onClick={() => setCurrentPage(page)}
                >
                  {page}
                </button>
              );
            })}

            <button
              className={`page-btn ${currentPage === totalPages ? 'disabled' : ''}`}
              onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
              disabled={currentPage === totalPages}
            >
              <span className="material-symbols-outlined">chevron_left</span>
            </button>
          </div>
        </div>
      </div>

      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف السجل"
        message="هل أنت متأكد من حذف هذه العملية؟"
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmState({ open: false, target: null })}
      />
    </div>
  );
}

export default Chemicals;