import React, { useEffect, useRef, useState, useMemo } from 'react';
import { Chart, registerables } from 'chart.js';
import { supabase } from '../../services/supabase';
import './Reports.css';

Chart.register(...registerables);

function Reports() {
  // --- Refs للرسوم البيانية ---
  const barChartRef = useRef(null);
  const doughnutRefs = useRef([]);
  const barChartInstance = useRef(null);
  const doughnutInstances = useRef([]);

  // --- States الأساسية ---
  const [activeTab, setActiveTab] = useState('أراضي');
  const [selectedYear, setSelectedYear] = useState('2026'); // تم ضبطه لعام 2026
  const [loading, setLoading] = useState(true);
  const [expenseFilter, setExpenseFilter] = useState('all');
  const [showAllExpenses, setShowAllExpenses] = useState(false);

  // --- States البيانات ---
  const [rawData, setRawData] = useState([]);
  const [allSeasons, setAllSeasons] = useState([]);

  // عند تغيير الفلتر، نغلق قائمة "عرض الكل" تلقائياً
  useEffect(() => {
    setShowAllExpenses(false);
  }, [expenseFilter, activeTab]);

  // 1. تنسيق العملة
  const formatEGP = (amount) => {
    return new Intl.NumberFormat('ar-EG', {
      style: 'currency',
      currency: 'EGP',
      maximumFractionDigits: 0
    }).format(amount || 0);
  };

  // 2. جلب البيانات من سوبابيز (الـ View الموحد والتقارير)
  useEffect(() => {
    const fetchBaseData = async () => {
      try {
        setLoading(true);
        const [reportsRes, seasonsRes] = await Promise.all([
          supabase.from('detailed_reports_view').select('*'),
          supabase.from('reports').select('*').eq('report_type', 'annual')
        ]);

        if (reportsRes.data) setRawData(reportsRes.data);

        if (seasonsRes.data) {
          const mapped = seasonsRes.data.map(s => {
            const d = typeof s.data === 'string' ? JSON.parse(s.data) : (s.data || {});
            return {
              name: `موسم ${d.season_name || 'الزراعي'}`,
              year: (d.year || '2026').toString(),
              percentage: parseInt(d.completion_rate) || 0,
              target: parseFloat(d.target) || 0,
              collected: parseFloat(d.collected) || 0,
              remaining: (parseFloat(d.target) || 0) - (parseFloat(d.collected) || 0),
              color: '#485935'
            };
          });
          setAllSeasons(mapped);
        }
      } catch (error) {
        console.error("Error fetching dashboard data:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchBaseData();
  }, []);

  // 3. معالجة البيانات (Computed Logic)
  const filteredData = useMemo(() => {
    if (selectedYear === 'الكل') return rawData;
    return rawData.filter(item => {
      if (!item.date) return false;
      return new Date(item.date).getFullYear().toString() === selectedYear;
    });
  }, [rawData, selectedYear]);

  const stats = useMemo(() => {
    const totalExp = filteredData.filter(d => d.type !== 'income').reduce((s, c) => s + Number(c.amount), 0);
    const totalInc = filteredData.filter(d => d.type === 'income').reduce((s, c) => s + Number(c.amount), 0);
    const profit = totalInc - totalExp;
    const evaluateExpenses = (amount) => {
      if (amount > 50000) {
        return { label: 'استهلاك كثيف', status: 'up' }; // كثيف
      } else if (amount >= 15000) {
        return { label: 'مستوى منضبط', status: 'stable' }; // منضبط
      } else {
        return { label: 'توفير ممتاز', status: 'down' }; // موفر
      }
    };
    return [
      { title: 'إجمالي المصاريف', value: formatEGP(totalExp), change: evaluateExpenses(totalExp).label, status: 'up', icon: 'payments' },
      { title: 'إجمالي الإيرادات', value: 'قريباً', change: '', status: 'up', icon: 'trending_up' },
      // { title: 'إجمالي الإيرادات', value: formatEGP(totalInc), change: 'محدث', status: 'up', icon: 'trending_up' },
      {
        title: 'صافي الربح',
        value: 'قريباً',
        // change: profit >= 0 ? 'ربح' : 'عجز',
        status: profit >= 0 ? 'up' : 'danger',
        icon: 'savings'
      },
      // { title: 'صافي الربح', value: {/*formatEGP(profit)*/}, change: profit >= 0 ? 'ربح' : 'عجز', status: profit >= 0 ? 'up' : 'danger', icon: 'savings' },
    ];
  }, [filteredData]);

  // 4. تحديث الرسوم البيانية
  useEffect(() => {
    if (loading) return;

    const months = [0, 1, 2, 3, 4, 5]; // النصف الأول
    const op = months.map(m => filteredData.filter(d => d.date && new Date(d.date).getMonth() === m && d.type !== 'income').reduce((s, c) => s + Number(c.amount), 0));
    const ad = months.map(m => filteredData.filter(d => d.date && new Date(d.date).getMonth() === m && d.category === 'administrative').reduce((s, c) => s + Number(c.amount), 0));

    if (barChartInstance.current) barChartInstance.current.destroy();
    doughnutInstances.current.forEach(instance => instance && instance.destroy());
    doughnutInstances.current = [];

    const initCharts = () => {
      if (barChartRef.current) {
        const ctx = barChartRef.current.getContext('2d');
        barChartInstance.current = new Chart(ctx, {
          type: 'bar',
          data: {
            labels: ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو'],
            datasets: [
              { label: 'تشغيلية', data: op, backgroundColor: '#485935', borderRadius: 4, barThickness: 15 },
              { label: 'إدارية', data: ad, backgroundColor: '#e2e5dc', borderRadius: 4, barThickness: 15 }
            ]
          },
          options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true } } }
        });
      }

      const seasonsToRender = selectedYear === 'الكل' ? allSeasons : allSeasons.filter(s => s.year === selectedYear);
      seasonsToRender.forEach((season, index) => {
        const canvas = doughnutRefs.current[index];
        if (canvas) {
          const instance = new Chart(canvas.getContext('2d'), {
            type: 'doughnut',
            data: { datasets: [{ data: [season.percentage, 100 - season.percentage], backgroundColor: [season.color, '#f0f0f0'], borderWidth: 0, circumference: 270, rotation: 225, cutout: '85%' }] },
            options: { responsive: true, maintainAspectRatio: false }
          });
          doughnutInstances.current.push(instance);
        }
      });
    };

    const timer = setTimeout(initCharts, 300);
    return () => clearTimeout(timer);
  }, [filteredData, activeTab, allSeasons, selectedYear, loading]);

  // --- دالة رندر المحتوى ---
  const renderTabContent = () => {
    switch (activeTab) {
      case 'أراضي':
        return (
          <div className="report-main-card table-card full-width">
            <div className="card-header"><h3>📊 الموقف المالي المجمع - موسم {selectedYear}</h3></div>
            <table className="land-table">
              <thead>
                <tr><th>البند المالي</th><th>الحالة</th><th>إجمالي المنصرف</th><th>ملاحظات المحاسبة</th><th>التحديث</th></tr>
              </thead>
              <tbody>
                <tr>
                  <td className="land-name-cell"><div className="land-icon"><span className="material-symbols-outlined">agriculture</span></div>النشاط الزراعي العام</td>
                  <td><span className="status-pill success">مستقر</span></td>
                  <td className="bold">{stats[0].value}</td>
                  <td>تجميع آلي من كافة الدفاتر</td>
                  <td><span className="date-tag">تحديث لحظي</span></td>
                </tr>
              </tbody>
            </table>
          </div>
        );

      case 'مصاريف':
        // 1. تعريف المتغير الأساسي
        const allExpenses = filteredData.filter(d => d.type !== 'income');

        // 2. التصفية بناءً على الفئة المختارة للجدول (دعمنا مسمى spray و spraying)
        const filteredExpenses = allExpenses.filter(item => {
          if (expenseFilter === 'all') return true;
          if (expenseFilter === 'spraying') {
            return item.category === 'spraying' || item.category === 'spray' || item.category === 'رش';
          }
          return item.category === expenseFilter;
        });

        // 3. تحديد ما يتم عرضه في الجدول
        const displayedExpenses = showAllExpenses ? filteredExpenses : filteredExpenses.slice(0, 5);

        // 4. الحسابات الإجمالية - تعديل الفلتر ليكون مرناً
        const laborTotal = allExpenses
          .filter(i => i.category === 'labor')
          .reduce((a, b) => a + Number(b.amount), 0);

        const chemicalTotal = allExpenses
          .filter(i => i.category === 'chemicals')
          .reduce((a, b) => a + Number(b.amount), 0);

        // هنا الحل: جعلنا الفلتر يقبل spray أو spraying أو رش
        const sprayItems = allExpenses.filter(i =>
          i.category === 'spraying' || i.category === 'spray' || i.category === 'رش'
        );
        const sprayTotal = sprayItems.reduce((a, b) => a + Number(b.amount), 0);

        return (
          <div className="reports-main-grid">
            <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>

              <div className="report-main-card chart-card">
                <div className="card-header">
                  <div className="header-info">
                    <h3>توزيع التكاليف الشهرية</h3>
                    <p>تحليل المقارنة بين المصاريف التشغيلية والإدارية</p>
                  </div>
                  <div className="header-badge">{selectedYear}</div>
                </div>
                <div className="bar-chart-container"><canvas ref={barChartRef}></canvas></div>
                <div className="chart-legend">
                  <div className="legend-item"><span className="dot admin"></span><span>إدارية</span></div>
                  <div className="legend-item"><span className="dot operational"></span><span>تشغيلية</span></div>
                </div>
              </div>


            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px', height: 'fit-content', }}>
              {/* إجماليات السايدبار */}
              <div className="profit-target" style={{ paddingBottom: '12px', borderBottom: '1px solid #f0f0f0' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <div style={{ display: 'flex', flexDirection: 'column' }}>
                    <span style={{ fontSize: '0.8rem', color: '#666' }}>إجمالي العمالة</span>
                    <span className="bold" style={{ fontSize: '1.1rem' }}>{formatEGP(laborTotal)}</span>
                  </div>
                  <span style={{ fontSize: '0.75rem', background: '#fff4e5', color: '#b07b00', padding: '2px 8px', borderRadius: '10px' }}>
                    {allExpenses.filter(i => i.category === 'labor').length} عمليات
                  </span>
                </div>
              </div>

              <div className="profit-target" style={{ paddingBottom: '12px', borderBottom: '1px solid #f0f0f0' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <div style={{ display: 'flex', flexDirection: 'column' }}>
                    <span style={{ fontSize: '0.8rem', color: '#666' }}>إجمالي الكيماوي</span>
                    <span className="bold" style={{ fontSize: '1.1rem' }}>{formatEGP(chemicalTotal)}</span>
                  </div>
                  <span style={{ fontSize: '0.75rem', background: '#e8f5e9', color: '#2e7d32', padding: '2px 8px', borderRadius: '10px' }}>
                    {allExpenses.filter(i => i.category === 'chemicals').length} عمليات
                  </span>
                </div>
              </div>

              <div className="profit-target" style={{ paddingBottom: '12px', borderBottom: '1px solid #f0f0f0' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <div style={{ display: 'flex', flexDirection: 'column' }}>
                    <span style={{ fontSize: '0.8rem', color: '#666' }}>إجمالي دورات الرش</span>
                    <span className="bold" style={{ fontSize: '1.1rem' }}>{formatEGP(sprayTotal)}</span>
                  </div>
                  <span style={{ fontSize: '0.75rem', background: '#e1f5fe', color: '#0288d1', padding: '2px 8px', borderRadius: '10px' }}>
                    {sprayItems.length} دورات
                  </span>
                </div>
              </div>

              <div className="profit-target" style={{ background: '#f9f9f9', padding: '12px', borderRadius: '12px', marginTop: '5px' }}>
                <span style={{ fontSize: '0.85rem', fontWeight: 'bold', color: '#1a1f14' }}>المجموع الصافي للمصاريف</span>
                <div className="bold" style={{ fontSize: '1.3rem', color: '#485935' }}>
                  {formatEGP(laborTotal + chemicalTotal + sprayTotal)}
                </div>
              </div>

              <div style={{ fontSize: '0.75rem', color: '#8a9178', fontStyle: 'italic', textAlign: 'center', marginTop: '10px' }}>
                * هذه البيانات بناءً على سجلات {selectedYear === 'الكل' ? 'كافة المواسم المسجلة' : `موسم ${selectedYear}`}
              </div>
            </div>
            <div className="report-main-card table-card" style={{ gridColumn: '1 / -1', width: '100%' }}>
              <div className="card-header" style={{ marginBottom: '10px' }}>
                <h3>سجل المصاريف</h3>
                <div className="reports-tabs" style={{ gap: '15px', borderBottom: 'none' }}>
                  <button className={expenseFilter === 'all' ? 'active' : ''} onClick={() => setExpenseFilter('all')}>الكل</button>
                  <button className={expenseFilter === 'labor' ? 'active' : ''} onClick={() => setExpenseFilter('labor')}>العمالة</button>
                  <button className={expenseFilter === 'chemicals' ? 'active' : ''} onClick={() => setExpenseFilter('chemicals')}>الكيماوي</button>
                  {/* إضافة زر الرش لفلترة الجدول */}
                  <button className={expenseFilter === 'spraying' ? 'active' : ''} onClick={() => setExpenseFilter('spraying')}>الرش</button>
                </div>
              </div>

              <table className="land-table" style={{ width: '100%' }}>
                <thead>
                  <tr><th>البند</th><th>الفئة</th><th>القيمة</th><th>التاريخ</th></tr>
                </thead>
                <tbody>
                  {displayedExpenses.length > 0 ? (
                    displayedExpenses.map((item, idx) => (
                      <tr key={idx}>
                        <td className="land-name-cell">
                          <div className="land-icon">
                            <span className="material-symbols-outlined" style={{ fontSize: '1.2rem' }}>
                              {item.category === 'labor' ? 'engineering' :
                                item.category === 'chemicals' ? 'science' : 'opacity'}
                            </span>
                          </div>
                          <span style={{ fontSize: '0.9rem' }}>{item.description || 'مصروف زراعي'}</span>
                        </td>
                        <td>
                          <span className={`status-pill ${item.category === 'labor' ? 'warning' :
                            item.category === 'chemicals' ? 'success' : 'info'}`}>
                            {item.category === 'labor' ? 'عمالة' :
                              item.category === 'chemicals' ? 'كيماوي' : 'رش'}
                          </span>
                        </td>
                        <td className="bold">{formatEGP(item.amount)}</td>
                        <td style={{ fontSize: '0.85rem', color: '#666' }}>
                          {item.date ? new Date(item.date).toLocaleDateString('ar-EG') : 'غير محدد'}
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr><td colSpan="4" style={{ textAlign: 'center', padding: '20px' }}>لا توجد بيانات لهذه الفئة</td></tr>
                  )}
                </tbody>
              </table>
              {filteredExpenses.length > 5 && (
                <div style={{ textAlign: 'center', marginTop: '15px' }}>
                  <button className="text-btn" onClick={() => setShowAllExpenses(!showAllExpenses)}>
                    {showAllExpenses ? 'عرض أقل' : `عرض كافة الـ (${filteredExpenses.length}) سجلات`}
                  </button>
                </div>
              )}
            </div>
          </div>
        ); case 'تصدير البيانات':
        return (


          <div className="export-card">
            <h3>تصدير البيانات</h3>
            <div className="export-buttons">
              <button className="btn-export-full">PDF</button>
              <button className="btn-export-outline">Excel</button>
            </div>
          </div>
        );
      case 'أرباح':
        return (
          <div className="empty-state-view">
            <h2>قريباً</h2>
            {/* <div className="seasons-grid">
              {allSeasons.filter(s => selectedYear === 'الكل' || s.year === selectedYear).map((season, index) => (
                <div className="report-main-card profits-card" key={index}>
                  <h3>{season.name} {season.year}</h3>
                  <div className="doughnut-container">
                    <canvas ref={el => doughnutRefs.current[index] = el}></canvas>
                    <div className="doughnut-center">
                      <span className="percentage">%{season.percentage}</span>
                      <span className="desc">من الهدف</span>
                    </div>
                  </div>
                  <div className="profits-details">
                    <div className="profit-target"><span>هدف التحصيل</span><span className="bold">{formatEGP(season.target)}</span></div>
                    <div className="profit-split">
                      <div className="split-item"><span>محصل: <span className="green">{formatEGP(season.collected)}</span></span></div>
                      <div className="split-item"><span>متبقي: <span className="red">{formatEGP(season.remaining)}</span></span></div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
            */}
          </div>
        );

      case 'إيرادات':
        const incomeItems = filteredData.filter(d => d.type === 'income');
        return (
          <div className="empty-state-view" style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', minHeight: '300px' }}>
            <h1>قريباً</h1>
            {/* <div className="report-main-card table-card full-width">
              <div className="card-header">
                <h3>دفتر مبيعات وإيرادات {selectedYear}</h3>
                <div className="header-badge">إجمالي: {stats[1].value}</div>
              </div>
              <table className="land-table">
                <thead>
                  <tr><th>المصدر / العميل</th><th>التاريخ</th><th>البيان</th><th>المبلغ</th><th>الحالة</th></tr>
                </thead>
                <tbody>
                  {incomeItems.map((row, i) => (
                    <tr key={i}>
                      <td>{row.source || 'عميل محلي'}</td>
                      <td>{row.date}</td>
                      <td>{row.description}</td>
                      <td className="bold" style={{ color: '#2e7d32' }}>{formatEGP(row.amount)}</td>
                      <td><span className="status-pill success">مكتمل</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            */}
          </div>
        ); default: return null;
    }
  };

  return (
    <div className="reports-container">
      <div className="reports-header-row">
        <div className="reports-tabs">
          {['أراضي', 'أرباح', 'إيرادات', 'مصاريف', 'تصدير البيانات'].map(t => (
            <button key={t} className={activeTab === t ? 'active' : ''} onClick={() => setActiveTab(t)}>
              {t === 'أراضي' ? 'ملخص التكاليف' : t === 'أرباح' ? 'أرباح المواسم' : t === 'إيرادات' ? 'تقرير الإيرادات' : t === 'مصاريف' ? 'تقرير المصاريف' : 'تصدير البيانات'}
            </button>
          ))}
        </div>
        <select value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)} className="filter-select">
          <option value="2026">موسم 2026</option>
          <option value="2025">موسم 2025</option>
          <option value="الكل">كل المواسم</option>
        </select>
      </div>

      <div className="reports-stats-grid">
        {stats.map((stat, index) => (
          <div className="report-stat-card" key={index}>
            <div className="stat-icon-wrapper"><span className="material-symbols-outlined">{stat.icon}</span></div>
            <div className="stat-content">
              <span className="stat-label">{stat.title}</span>
              <div className="stat-value-row">
                <span className="stat-amount">{stat.value}</span>
                <span className={`stat-badge ${stat.amount > 50000 ? 'danger' :
                  stat.amount >= 15000 ? 'warning' :
                    'success'
                  }`}>
                  {stat.change}
                </span>              </div>
            </div>
          </div>
        ))}
      </div>
      {loading ? <div className="loading-shimmer">جاري التحميل...</div> : renderTabContent()}
    </div>
  );
}

export default Reports;