import { supabase } from './supabase';

/**
 * الحصول على جميع سجلات العمالة لمزرعة معينة
 */
export const getLaborLogs = async (farmId, limit = 100, offset = 0) => {
    try {
        const { data, error, count } = await supabase
            .from('labor')
            .select('*', { count: 'exact' })
            .eq('farm_id', farmId)
            .order('date', { ascending: false })
            .range(offset, offset + limit - 1);

        if (error) throw error;
        return { success: true, data, count };
    } catch (error) {
        return { success: false, error: error.message };
    }
};

/**
 * إضافة سجل عمالة جديد
 */
export const addLaborLog = async (taskData) => { // شيل farmId
    try {
        const { data, error } = await supabase.from('labor').insert([
            {
                worker_name: taskData.workerName,
                task_type: taskData.taskType,
                task_tag: taskData.taskTag,
                date: taskData.date,
                amount: taskData.amount,
                payment_status: taskData.paymentStatus,
                payment_status_type: taskData.paymentStatusType,
                created_at: new Date().toISOString(),
            },
        ]).select();

        if (error) throw error;
        return { success: true, data };
    } catch (error) {
        return { success: false, error: error.message };
    }
};

/**
 * تحديث سجل عمالة (تعديل بيانات أو حالة دفع)
 */
export const updateLaborLog = async (logId, taskData) => {
    try {
        const { data, error } = await supabase
            .from('labor')
            .update({
                worker_name: taskData.workerName,
                task_type: taskData.taskType,
                task_tag: taskData.taskTag,
                date: taskData.date,
                amount: taskData.amount,
                payment_status: taskData.paymentStatus,
                payment_status_type: taskData.paymentStatusType,
                updated_at: new Date().toISOString(),
            })
            .eq('id', logId)
            .select();

        if (error) throw error;
        return { success: true, data };
    } catch (error) {
        return { success: false, error: error.message };
    }
};

/**
 * حذف سجل عمالة
 */
export const deleteLaborLog = async (logId) => {
    try {
        const { error } = await supabase
            .from('labor')
            .delete()
            .eq('id', logId);

        if (error) throw error;
        return { success: true };
    } catch (error) {
        return { success: false, error: error.message };
    }
};

/**
 * إحصائيات سريعة للداشبورد (إجمالي اليوم، المهام المعلقة)
 */
export const getLaborStats = async (farmId) => {
    try {
        const today = new Date().toISOString().slice(0, 10);

        // جلب بيانات اليوم والبيانات غير المدفوعة
        const { data, error } = await supabase
            .from('labor')
            .select('amount, payment_status_type, date')
            .eq('farm_id', farmId);

        if (error) throw error;

        const stats = {
            totalToday: data.filter(d => d.date === today).length,
            pendingCount: data.filter(d => d.payment_status_type === 'pending').length,
            totalUnpaidAmount: data.filter(d => d.payment_status_type !== 'paid')
                .reduce((sum, item) => sum + Number(item.amount), 0)
        };

        return { success: true, data: stats };
    } catch (error) {
        return { success: false, error: error.message };
    }
};