import React, { useEffect, useRef, useState, useMemo } from 'react';
import { Chart, registerables } from 'chart.js';
import { fetchOverviewData } from '../../services/overview';
import './Overview.css';

Chart.register(...registerables);

function Overview() {
  const chartRef = useRef(null);
  const chartInstance = useRef(null);
  const [loading, setLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [rawTableData, setRawTableData] = useState([]);
  const [stats, setStats] = useState({ totalExpenses: 0, totalIncome: 0, profit: 0, laborCount: 0, sprayCount: 0 });
  const [breakdown, setBreakdown] = useState({ labor: 0, chemicals: 0, spray: 0 });

  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState('all');

  // قاموس لترجمة الأنواع للعربية
  const typeTranslations = {
    expense: 'مصروفات',
    income: 'إيرادات',
    labor: 'عمالة',
    spray: 'رش',
    irrigation: 'ري',
    chemical: 'كيماوي'
  };

  // 1. التحميل الأولي عند فتح الصفحة (بدون ريفريش للمتصفح)
  useEffect(() => {
    const initialLoad = async () => {
      try {
        const data = await fetchOverviewData();
        if (data) {
          setStats(data.stats);
          setBreakdown(data.breakdown);
          setRawTableData(data.activities || []);
        }
      } catch (error) {
        console.error("خطأ في التحميل الأولي:", error);
      } finally {
        setLoading(false);
      }
    };
    initialLoad();
  }, []);

  // 2. دالة التحديث اليدوي (عند الضغط على الزرار فقط)
  const handleManualRefresh = async () => {
    try {
      setIsRefreshing(true);
      // نجلب الداتا أولاً للتأكد أن السيرفر مستجيب
      const data = await fetchOverviewData();
      if (data) {
        console.log("تمت المزامنة، جاري تحديث الصفحة بالكامل...");
        // الريفريش الفعلي (F5)
        window.location.reload();
      }
    } catch (error) {
      console.error("فشل التحديث اليدوي:", error);
      setIsRefreshing(false);
    }
  };

  const filteredActivities = useMemo(() => {
    const dataToFilter = rawTableData || [];
    return dataToFilter.filter(act => {
      const description = act?.title || act?.description || '';
      const matchesSearch = description.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = typeFilter === 'all' || act?.type === typeFilter;
      return matchesSearch && matchesType;
    });
  }, [searchTerm, typeFilter, rawTableData]);

  const formatEGP = (val) => new Intl.NumberFormat('ar-EG', {
    style: 'currency',
    currency: 'EGP',
    maximumFractionDigits: 0
  }).format(val || 0);

  // رسم الرسم البياني
  useEffect(() => {
    if (loading || !chartRef.current) return;
    const ctx = chartRef.current.getContext('2d');
    if (chartInstance.current) chartInstance.current.destroy();

    chartInstance.current = new Chart(ctx, {
      type: 'line',
      data: {
        labels: ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو'],
        datasets: [
          {
            label: 'الإيرادات',
            data: [stats.totalIncome * 0.4, stats.totalIncome * 0.6, stats.totalIncome * 0.8, stats.totalIncome],
            borderColor: '#485935',
            backgroundColor: 'rgba(72, 89, 53, 0.1)',
            fill: true,
            tension: 0.4
          },
          {
            label: 'المصاريف',
            data: [stats.totalExpenses * 0.3, stats.totalExpenses * 0.7, stats.totalExpenses * 0.5, stats.totalExpenses],
            borderColor: '#e74c3c',
            borderDash: [5, 5],
            tension: 0.4
          }
        ]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { position: 'bottom', labels: { font: { family: 'Cairo' } } }
        }
      }
    });
  }, [loading, stats]);

  if (loading) return (
    <div className="loading-container">
      <div className="loader"></div>
      <p>جاري مزامنة ميزان الديوان...</p>
    </div>
  );

  return (
    <div className="overview-page">
      <div className="page-header">
        <h1>ميزان الديوان</h1>
        <button
          onClick={handleManualRefresh}
          className={`refresh-btn-modern ${isRefreshing ? 'spinning' : ''}`}
          disabled={isRefreshing}
        >
          <span className="material-symbols-outlined">sync</span>
          {isRefreshing ? 'جاري التحديث...' : 'تحديث البيانات'}
        </button>
      </div>

      <div className="stats-grid">
        <StatCard title="إجمالي المصاريف" value={formatEGP(stats.totalExpenses)} icon="payments" color="red" />
        <StatCard title="إجمالي الإيرادات" value={formatEGP(stats.totalIncome)} icon="trending_up" color="green" />
        <StatCard title="صافي الربح" value="قريباً" icon="account_balance_wallet" color="gold" />
        {/* <StatCard title="صافي الربح" value={formatEGP(stats.profit)} icon="account_balance_wallet" color="gold" /> */}
        <StatCard title="العمالة النشطة" value={stats.laborCount} icon="engineering" color="blue" />
        <StatCard title="دورات الرش" value={stats.sprayCount} icon="opacity" color="cyan" />
      </div>

      <div className="charts-row">
        <div className="chart-container-main glass-card">
          <div className="chart-header">
            <h3>تحليل الأداء المالي</h3>
          </div>
          <div className="chart-wrapper"><canvas ref={chartRef}></canvas></div>
        </div>

        <div className="expenses-breakdown glass-card">
          <h3>هيكل التكاليف الأساسي</h3>
          <div className="expense-list">
            <ProgressBar name="أجور العمالة" amount={breakdown.labor} total={stats.totalExpenses} color="#485935" />
            <ProgressBar name="أسمدة وكيماويات" amount={breakdown.chemicals} total={stats.totalExpenses} color="#8a9178" />
            <ProgressBar name="تكاليف الرش" amount={breakdown.spray} total={stats.totalExpenses} color="#e67e22" />
          </div>
          <div className="total-badge">إجمالي المنصرف: {formatEGP(stats.totalExpenses)}</div>
        </div>
      </div>

      <div className="activities-section glass-card">
        <div className="section-header">
          <h3>سجل كافة العمليات (عرض فقط)</h3>
          <div className="header-controls">
            <input
              type="text"
              placeholder="ابحث في الوصف أو البيان..."
              className="search-input"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <select className="filter-select" value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)}>
              <option value="all">كل السجلات</option>
              <option value="expense">مصاريف عامة</option>
              <option value="income">إيرادات</option>
              <option value="labor">عمالة</option>
              <option value="spray">رش</option>
              <option value="irrigation">ري</option>
            </select>
          </div>
        </div>

        <div className="table-responsive full-log">
          <table className="activities-table">
            <thead>
              <tr>
                <th>النوع</th>
                <th>البيان / الوصف</th>
                <th>التاريخ</th>
                <th>القيمة</th>
                <th>التصنيف</th>
              </tr>
            </thead>
            <tbody>
              {filteredActivities.length > 0 ? filteredActivities.map((act, i) => (
                <tr key={i} className="fade-in-row">
                  <td>
                    <span className={`type-tag ${act.type}`}>
                      {typeTranslations[act.type] || act.type}
                    </span>
                  </td>
                  <td className="bold">{act.title || act.description || 'بدون بيان'}</td>
                  <td>{new Date(act.date || act.created_at).toLocaleDateString('ar-EG')}</td>
                  <td className={`amount-cell ${act.type === 'income' ? 'plus' : 'minus'}`}>
                    {act.type === 'income' ? '+' : '-'} {formatEGP(act.amount)}
                  </td>
                  <td>{act.category || 'عام'}</td>
                </tr>
              )) : (
                <tr>
                  <td colSpan="5" style={{ textAlign: 'center', padding: '30px', color: '#666' }}>
                    لا توجد سجلات حالياً.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// مكونات مساعدة
const StatCard = ({ title, value, icon, color }) => (
  <div className={`stat-card border-${color}`}>
    <div className="stat-header"><span className="stat-title">{title}</span></div>
    <div className="stat-body">
      <span className="stat-value">{value}</span>
      <div className={`stat-icon-bg bg-${color}`}><span className="material-symbols-outlined">{icon}</span></div>
    </div>
  </div>
);

const ProgressBar = ({ name, amount, total, color }) => {
  const percentage = total > 0 ? Math.round((amount / total) * 100) : 0;
  return (
    <div className="expense-item">
      <div className="expense-info"><span>{name}</span><span className="bold">{percentage}%</span></div>
      <div className="progress-bar"><div className="progress-fill" style={{ width: `${percentage}%`, backgroundColor: color }}></div></div>
      <div className="expense-amount-sub">{new Intl.NumberFormat('ar-EG').format(amount || 0)} ج.م</div>
    </div>
  );
};

export default Overview;