import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { signIn } from '../../services/auth';
import './Auth.css';

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(true); // تفعيل تذكرني افتراضياً
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // 1. التحقق من إدخال البيانات
    if (!email || !password) {
      setError('يرجى ملء جميع الحقول');
      setLoading(false);
      return;
    }

    try {
      // 2. استدعاء Supabase Login
      // ملاحظة: Supabase يتعامل مع "تذكرني" تلقائياً عبر LocalStorage
      const result = await signIn(email, password);

      if (result.success) {
        // 3. التوجيه للداشبورد
        // نستخدم replace: true لمنع المستخدم من العودة لصفحة اللوجين بالزر الخلفي
        navigate('/dashboard', { replace: true });
      } else {
        // تخصيص رسائل الخطأ لتكون أوضح بالعربي
        const errorMsg = result.error.includes('Invalid login credentials') 
          ? 'خطأ في البريد الإلكتروني أو كلمة المرور' 
          : result.error;
        setError(errorMsg);
      }
    } catch (err) {
      setError('حدث خطأ غير متوقع، حاول مرة أخرى');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page" dir="rtl">
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <Link to="/" className="auth-logo">
              ديوان <span className="logo-accent">الأرض</span>
            </Link>
            <h2>تسجيل الدخول</h2>
            <p>مرحباً بك مجدداً في نظامك المفضل</p>
          </div>

          <form className="auth-form" onSubmit={handleSubmit}>
            <div className="form-group">
              <label>البريد الإلكتروني</label>
              <div className="input-icon-group">
                <span className="material-symbols-outlined">mail</span>
                <input
                  type="email"
                  placeholder="email@example.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  disabled={loading}
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label>كلمة المرور</label>
              <div className="input-icon-group">
                <span className="material-symbols-outlined">lock</span>
                <input
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={loading}
                  required
                />
              </div>
            </div>

            {error && (
              <div className="error-message" style={{ color: '#d93025', backgroundColor: '#fdecea', padding: '10px', borderRadius: '4px', marginBottom: '15px', fontSize: '14px', display: 'flex', alignItems: 'center', gap: '5px' }}>
                <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>error</span>
                {error}
              </div>
            )}

            <div className="auth-options">
              <label className="remember-me" style={{ cursor: 'pointer' }}>
                <input 
                  type="checkbox" 
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.target.checked)}
                />
                <span>تذكرني</span>
              </label>
              <Link to="/forgot-password">نسيت كلمة المرور؟</Link>
            </div>

            <button type="submit" className="btn-primary-custom btn-full" disabled={loading}>
              {loading ? (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}>
                   <span>جاري التحميل...</span>
                </div>
              ) : 'دخول'}
            </button>
          </form>

          <div className="auth-footer">
            <p>ليس لديك حساب؟ <Link to="/register">إنشاء حساب جديد</Link></p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;