import { supabase } from './supabase';

export const userService = {
    // جلب بيانات المستخدم الحالي
    async getCurrentUserProfile(userId) {
        try {
            const { data, error } = await supabase
                .from('users')
                .select('*')
                .eq('id', userId)
                .single();
            
            if (error) throw error;
            return { success: true, data };
        } catch (error) {
            return { success: false, error: error.message };
        }
    },

    // تحديث بيانات المستخدم
    async updateProfile(userId, updates) {
        try {
            const { data, error } = await supabase
                .from('users')
                .update(updates)
                .eq('id', userId);
            
            if (error) throw error;
            return { success: true, data };
        } catch (error) {
            return { success: false, error: error.message };
        }
    },

    // حذف الحساب (من جدول users ومن الـ Auth)
    async deleteAccount() {
        try {
            // ملاحظة: حذف الحساب من الـ Auth يتطلب عادة Edge Function في Supabase
            // ولكن سنقوم هنا بحذف بياناته من جدول الـ users كخطوة أساسية
            const { error } = await supabase.rpc('delete_user_account'); // لو عامل RPC
            
            // الحل البسيط: تسجيل خروج وتنبيه الإدارة (أو استخدام الدالة المباشرة لو مفعلة)
            const { error: deleteError } = await supabase.from('users').delete().eq('id', (await supabase.auth.getUser()).data.user.id);
            
            if (deleteError) throw deleteError;
            return { success: true };
        } catch (error) {
            return { success: false, error: error.message };
        }
    }
};