import { supabase } from './supabase';

// دالة مساعدة للحصول على معرف المستخدم الحالي
const getCurrentuser_id = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    return user?.id;
};

// الحصول على المصروفات من الـ View الشامل
// src/services/expenses.js

export const getExpenses = async () => {
    try {
        const user_id = await getCurrentuser_id();
        const { data, error } = await supabase
            .from('all_farm_expenses') // تأكد من الاسم هنا
            .select('*')
            .eq('user_id', user_id)
            .order('date', { ascending: false });
        if (error) throw error;
        return { success: true, data };
    } catch (error) {
        console.error("Supabase Error:", error);
        return { success: false, error: error.message };
    }
};

// الحصول على المصروفات مجمعة حسب الفئة من الـ View
export const getExpensesByCategory = async () => {
    try {
        const user_id = await getCurrentuser_id();
        const { data, error } = await supabase
            .from('all_farm_expenses')
            .select('category, amount')
            .eq('user_id', user_id);

        if (error) throw error;

        const grouped = data.reduce((acc, expense) => {
            const category = expense.category || 'other';
            acc[category] = (acc[category] || 0) + Number(expense.amount);
            return acc;
        }, {});

        return { success: true, data: grouped };
    } catch (error) {
        return { success: false, error: error.message };
    }
};

// إضافة مصروف جديد (على الجدول الأصلي)
export const addExpense = async (expenseData) => {
    try {
        const user_id = await getCurrentuser_id();
        const { data, error } = await supabase
            .from('expenses') // الإضافة دائماً تكون في الجدول الأساسي
            .insert([{
                user_id,
                category: expenseData.category,
                amount: expenseData.amount,
                date: expenseData.date,
                description: expenseData.description,
            }])
            .select();

        if (error) throw error;
        return { success: true, data };
    } catch (error) {
        return { success: false, error: error.message };
    }
};

// !!! التعديل هنا: إضافة دالة التحديث المفقودة !!!
export const updateExpense = async (expenseId, expenseData) => {
    try {
        const { data, error } = await supabase
            .from('expenses')
            .update({
                category: expenseData.category,
                amount: expenseData.amount,
                date: expenseData.date,
                description: expenseData.description,
            })
            .eq('id', expenseId);

        if (error) throw error;
        return { success: true, data };
    } catch (error) {
        return { success: false, error: error.message };
    }
};

// حذف مصروفة (من الجدول الأصلي)
export const deleteExpense = async (expenseId) => {
    try {
        const { error } = await supabase
            .from('expenses')
            .delete()
            .eq('id', expenseId);

        if (error) throw error;
        return { success: true };
    } catch (error) {
        return { success: false, error: error.message };
    }
};
// إجمالي المصروفات من الـ View
export const getTotalExpenses = async (startDate = null, endDate = null) => {
    try {
        const user_id = await getCurrentuser_id();
        let query = supabase
            .from('all_farm_expenses') // القراءة من الـ View
            .select('amount')
            .eq('user_id', user_id);

        if (startDate) query = query.gte('date', startDate);
        if (endDate) query = query.lte('date', endDate);

        const { data, error } = await query;
        if (error) throw error;

        const total = data.reduce((sum, item) => sum + (Number(item.amount) || 0), 0);
        return { success: true, total };
    } catch (error) {
        return { success: false, error: error.message };
    }
};