import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { userService } from '../../services/account';
import { signOut } from '../../services/auth';
import { supabase } from '../../services/supabase';
import ConfirmDialog from '../../components/common/ConfirmDialog';
import './Account.css';

function Account() {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [user, setUser] = useState(null);
    const [formData, setFormData] = useState({ full_name: '', phone: '' });

    // حالات جديدة للحذف بكلمة المرور
    const [deletePassword, setDeletePassword] = useState('');
    const [isDeleting, setIsDeleting] = useState(false);

    const [showEditForm, setShowEditForm] = useState(false);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    const [notification, setNotification] = useState(null);

    useEffect(() => {
        fetchUserData();
    }, []);

    const fetchUserData = async () => {
        const { data: { user: authUser } } = await supabase.auth.getUser();
        if (authUser) {
            const result = await userService.getCurrentUserProfile(authUser.id);
            if (result.success) {
                setUser(result.data);
                setFormData({
                    full_name: result.data.full_name || '',
                    phone: result.data.phone || ''
                });
            }
        }
        setLoading(false);
    };

    const handleSaveEdit = async (e) => {
        e.preventDefault();
        setLoading(true);
        const result = await userService.updateProfile(user.id, formData);

        if (result.success) {
            setNotification('تم تحديث البيانات بنجاح');
            setUser({ ...user, ...formData });
            setShowEditForm(false);
        } else {
            setNotification('خطأ: ' + result.error);
        }
        setLoading(false);
        setTimeout(() => setNotification(null), 3000);
    };

    // الدالة المعدلة للتحقق من كلمة المرور قبل الحذف
    const confirmDelete = async () => {
        if (!deletePassword) {
            setNotification('يرجى إدخال كلمة المرور للتأكيد');
            return;
        }

        setIsDeleting(true);

        // 1. التحقق من صحة كلمة المرور عبر محاولة تسجيل الدخول مرة أخرى
        const { error: authError } = await supabase.auth.signInWithPassword({
            email: user.email,
            password: deletePassword,
        });

        if (authError) {
            setNotification('كلمة المرور غير صحيحة. لا يمكن حذف الحساب.');
            setIsDeleting(false);
            setTimeout(() => setNotification(null), 3000);
            return;
        }

        // 2. إذا كانت صحيحة، ابدأ عملية الحذف
        const result = await userService.deleteAccount();
        if (result.success) {
            await signOut();
            navigate('/');
        } else {
            setNotification('فشل الحذف: ' + result.error);
            setIsDeleting(false);
        }
    };

    const handleLogout = async () => {
        await signOut();
        navigate('/login');
    };

    if (loading && !user) return <div className="loading">جاري التحميل...</div>;

    return (
        <div className="account-page">
            {notification && <div className="notification-banner">{notification}</div>}

            <div className="account-card">
                {showEditForm ? (
                    <form onSubmit={handleSaveEdit} className="edit-form">
                        <h2>تعديل بيانات الحساب</h2>
                        <div className="form-group">
                            <label>الاسم الكامل</label>
                            <div className="input-icon-group">
                                <span className="material-symbols-outlined">person</span>
                                <input
                                    type="text"
                                    value={formData.full_name}
                                    onChange={(e) => setFormData({ ...formData, full_name: e.target.value })}
                                    placeholder="أدخل الاسم الكامل"
                                    required
                                />
                            </div>
                        </div>

                        <div className="form-group">
                            <label>رقم الهاتف</label>
                            <div className="input-icon-group">
                                <span className="material-symbols-outlined">phone</span>
                                <input
                                    type="text"
                                    value={formData.phone}
                                    onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                                    placeholder="01xxxxxxxxx"
                                />
                            </div>
                        </div>

                        <div className="form-actions">
                            <button type="submit" className="btn-primary" disabled={loading}>
                                {loading ? 'جاري الحفظ...' : 'حفظ التغييرات'}
                            </button>
                            <button type="button" onClick={() => setShowEditForm(false)} className="btn-secondary">
                                إلغاء
                            </button>
                        </div>
                    </form>
                ) : (
                    <>
                        <div className="account-header">
                            <div className="account-avatar">
                                <span className="material-symbols-outlined"> <img
                                    src="https://api.dicebear.com/7.x/avataaars/svg?seed=mohamed"
                                    alt="User"
                                    className="topbar-avatar"
                                    style={{ borderRadius: "35%" }}
                                /></span>                            </div>
                            <div className="account-info">
                                <h2 className="account-name">{user?.full_name || 'مستخدم جديد'}</h2>
                                <p className="account-email">{user?.email}</p>
                            </div>
                        </div>

                        <div className="account-details">
                            <h3>تفاصيل الحساب</h3>
                            <div className="details-grid">
                                <div>
                                    <span className="detail-label">رقم الهاتف</span>
                                    <span className="detail-value">{user?.phone || 'غير مسجل'}</span>
                                </div>
                                <div>
                                    <span className="detail-label">الصلاحية (Role)</span>
                                    <span className="detail-value">{user?.role || 'user'}</span>
                                </div>
                                <div>
                                    <span className="detail-label">تاريخ الإنشاء</span>
                                    <span className="detail-value">{new Date(user?.created_at).toLocaleDateString('ar-EG')}</span>
                                </div>
                                <div>
                                    <span className="detail-label">معرف المستخدم (ID)</span>
                                    <span className="detail-value" style={{ fontSize: '10px' }}>{user?.id}</span>
                                </div>
                            </div>
                        </div>

                        <div className="account-actions">
                            <button className="btn-secondary" onClick={() => setShowEditForm(true)}>تعديل الحساب</button>
                            <button className="btn-logout" onClick={() => setShowLogoutConfirm(true)}>تسجيل الخروج</button>
                            <button className="btn-danger" onClick={() => setShowDeleteConfirm(true)}>حذف الحساب</button>
                        </div>
                    </>
                )}
            </div>

            {/* نافذة تأكيد الحذف المطورة تطلب الباسورد */}
            <ConfirmDialog
                open={showDeleteConfirm}
                title="تأكيد حذف الحساب نهائياً"
                message={
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                        <p>سيتم مسح كافة بياناتك. يرجى إدخال كلمة المرور للمتابعة:</p>
                        <div className="input-icon-group">
                            <span className="material-symbols-outlined">lock</span>
                            <input
                                type="password"
                                placeholder="كلمة المرور"
                                value={deletePassword}
                                onChange={(e) => setDeletePassword(e.target.value)}
                                style={{ width: '100%', padding: '10px 40px 10px 10px', borderRadius: '8px', border: '1px solid #ddd' }}
                            />
                        </div>
                    </div>
                }
                confirmLabel={isDeleting ? "جاري الحذف..." : "تأكيد الحذف"}
                onConfirm={confirmDelete}
                onCancel={() => {
                    setShowDeleteConfirm(false);
                    setDeletePassword(''); // تصفير الحقل عند الإلغاء
                }}
            />

            <ConfirmDialog
                open={showLogoutConfirm}
                title="تسجيل الخروج"
                message="هل تريد الخروج من حسابك الحالي؟"
                confirmLabel="خروج"
                onConfirm={handleLogout}
                onCancel={() => setShowLogoutConfirm(false)}
            />
        </div>
    );
}

export default Account;