import { supabase } from './supabase';

export const irrigationService = {
  async getAll() {
    const { data, error } = await supabase
      .from('irrigation')
      .select('*')
      .order('created_at', { ascending: false });
    if (error) throw error;
    return data;
  },

// داخل ملف src/services/irrigation.js

async create(payload) {
  // جلب المستخدم الحالي برمجياً داخل السيرفس
  const { data: { user } } = await supabase.auth.getUser();
  
  if (!user) throw new Error("User not authenticated");

  const { data, error } = await supabase
    .from('irrigation')
    .insert([{ ...payload, user_id: user.id }]) // دمج الـ user_id هنا
    .select()
    .single();

  if (error) throw error;
  return data;
},

  async update(id, payload) {
    const { data, error } = await supabase
      .from('irrigation')
      .update(payload)
      .eq('id', id)
      .select()
      .single();
    if (error) throw error;
    return data;
  },

  async delete(id) {
    const { error } = await supabase
      .from('irrigation')
      .delete()
      .eq('id', id);
    if (error) throw error;
  }
};