import React, { useMemo, useState, useEffect } from 'react';
import './Expenses.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';
import { getExpenses, addExpense, updateExpense, deleteExpense } from '../../services/expenses';

function Expenses() {
  const [expenses, setExpenses] = useState([]);
  const [mode, setMode] = useState('list'); // 'list' | 'form'
  const [editingExpense, setEditingExpense] = useState(null);
  const [categoryFilter, setCategoryFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const pageSize = 6;
  const [confirmState, setConfirmState] = useState({ open: false, target: null });

  // 1. دالة جلب البيانات (جعلناها مستقلة لتكون مرئية لكل الـ Handles)
  const loadData = async () => {
    setLoading(true);
    setError('');
    try {
      const result = await getExpenses();
      if (result.success) {
        setExpenses(result.data || []);
      } else {
        setError(result.error || 'خطأ في تحميل المصروفات');
      }
    } catch (err) {
      console.error(err);
      setError('خطأ في تحميل البيانات');
    } finally {
      setLoading(false);
    }
  };

  // 2. استدعاء البيانات عند أول تحميل للصفحة
  useEffect(() => {
    loadData();
  }, []); // لو بتستخدم useLocation من react-router-dom

  // 3. الحسابات والفلترة (Logic)
  const totalAmount = useMemo(
    () => expenses.reduce((sum, e) => sum + (Number(e.amount) || 0), 0),
    [expenses]
  );

  const filteredExpenses = useMemo(() => {
    return expenses.filter((e) => {
      const matchesCategory = categoryFilter === 'all' ? true : e.category === categoryFilter;
      const matchesSearch = !searchTerm || e.description.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [expenses, categoryFilter, searchTerm]);

  const topCategory = useMemo(() => {
    if (expenses.length === 0) return { name: 'لا يوجد', percent: 0 };

    const totals = expenses.reduce((acc, exp) => {
      acc[exp.category] = (acc[exp.category] || 0) + (Number(exp.amount) || 0);
      return acc;
    }, {});

    const top = Object.entries(totals).reduce((a, b) => (b[1] > a[1] ? b : a));
    const percent = totalAmount > 0 ? ((top[1] / totalAmount) * 100).toFixed(0) : 0;

    const labels = { labor: 'العمالة', chemicals: 'الكيماويات', irrigation: 'الري', fuel: 'الوقود', other: 'أخرى' };
    return { name: labels[top[0]] || top[0], percent };
  }, [expenses, totalAmount]);

  const totalPages = Math.max(1, Math.ceil(filteredExpenses.length / pageSize));

  const pagedExpenses = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return filteredExpenses.slice(start, start + pageSize);
  }, [filteredExpenses, currentPage]);

  // 4. معالجة الأحداث (Handles)
  const handleAddExpense = () => {
    setEditingExpense({
      id: null,
      category: 'other',
      description: '',
      date: new Date().toISOString().slice(0, 10),
      amount: 0,
    });
    setMode('form');
  };

  const handleEditExpense = (expense) => {
    // نرسل الـ id الأصلي وليس الـ unique_id
    setEditingExpense({ ...expense, id: expense.id });
    setMode('form');
  };

  const handleDeleteExpense = (expense) => {
    setConfirmState({ open: true, target: expense });
  };

  const handleConfirmDelete = async () => {
    const target = confirmState.target;
    if (!target) return;

    try {
      // نستخدم الـ id الأصلي المخزن في الـ View
      const result = await deleteExpense(target.id);
      if (result.success) {
        await loadData();
      } else {
        setError('خطأ في حذف المصروف');
      }
    } catch (err) {
      setError('خطأ: ' + err.message);
    }
    setConfirmState({ open: false, target: null });
  };

  const handleCancelDelete = () => {
    setConfirmState({ open: false, target: null });
  };

  const handleFormChange = (field, value) => {
    setEditingExpense((prev) => ({ ...prev, [field]: value }));
  };

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    if (!editingExpense) return;

    setLoading(true);
    setError('');

    try {
      const isNew = editingExpense.id == null;
      const expensePayload = {
        category: editingExpense.category,
        description: editingExpense.description,
        date: editingExpense.date,
        amount: parseFloat(editingExpense.amount) || 0,
      };

      let result;
      if (isNew) {
        result = await addExpense(expensePayload);
      } else {
        result = await updateExpense(editingExpense.id, expensePayload);
      }

      if (result.success) {
        // بدلاً من التحديث اليدوي للـ state، نسحب البيانات الجديدة بالكامل من الـ View
        await loadData();
        setMode('list');
        setEditingExpense(null);
      } else {
        setError(result.error || 'خطأ في حفظ البيانات');
      }
    } catch (err) {
      console.error("Submit Error:", err);
      setError('حدث خطأ غير متوقع: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleFormCancel = () => {
    setMode('list');
    setEditingExpense(null);
  };

  // --- نهاية اللوجيك وبداية الـ Render ---
  return (
    <div className="expenses-page">
      {error && <div style={{ color: 'red', padding: '10px', marginBottom: '10px' }}>{error}</div>}
      {loading && <div>جاري التحميل...</div>}

      {!loading && (
        <>
          <div className="expenses-header-row">
            <h1 className="expenses-title">إدارة المصاريف</h1>
            {mode === 'list' && (
              <button className="btn-primary" onClick={handleAddExpense}>
                <span className="material-symbols-outlined">add</span>
                إضافة مصروف جديد
              </button>
            )}
          </div>

          <p className="expenses-subtitle">
            متابعة كل الفلوس اللي بتتصرف عشان ضبط الحسابات.
          </p>

          {mode === 'form' && editingExpense ? (
            <div className="exp-card expenses-form-card">
              <h2 className="form-title">
                {editingExpense.id == null ? 'إضافة مصروف' : 'تعديل مصروف'}
              </h2>
              <form className="expenses-form" onSubmit={handleFormSubmit}>
                <div className="form-row">
                  <label>الوصف</label>
                  <input
                    type="text"
                    value={editingExpense.description}
                    onChange={(e) => handleFormChange('description', e.target.value)}
                    required
                  />
                </div>
                <div className="form-row">
                  <label>الفئة</label>
                  <select
                    value={editingExpense.category}
                    onChange={(e) => handleFormChange('category', e.target.value)}
                  >
                    <option value="labor">عمالة</option>
                    <option value="chemicals">كيماويات</option>
                    <option value="irrigation">رش</option>
                    <option value="fuel">وقود</option>
                    <option value="other">أخرى</option>
                  </select>
                </div>
                <div className="form-row two-cols">
                  <div>
                    <label>التاريخ</label>
                    <input
                      type="date"
                      value={editingExpense.date}
                      onChange={(e) => handleFormChange('date', e.target.value)}
                    />
                  </div>
                  <div>
                    <label>المبلغ (ج.م)</label>
                    <input
                      type="number"
                      value={editingExpense.amount}
                      onChange={(e) => handleFormChange('amount', e.target.value)}
                      min="0"
                    />
                  </div>
                </div>
                <div className="form-actions">
                  <button type="button" className="btn-secondary" onClick={handleFormCancel}>
                    إلغاء
                  </button>
                  <button type="submit" className="btn-primary">
                    حفظ
                  </button>
                </div>
              </form>
            </div>
          ) : (
            <>
              {/* Stats */}
              <div className="expenses-stats-row">
                <div className="exp-card stat-card">
                  <span className="stat-label">إجمالي المصاريف</span>
                  <span className="stat-value">
                    {totalAmount.toLocaleString('ar-EG')} ج.م
                  </span>
                </div>
                <div className="exp-card stat-card">
                  <span className="stat-label">أكثر فئة صرفت فيها</span>
                  <span className="stat-value">{topCategory.name}</span>
                  <span className="stat-note">حوالي {topCategory.percent}% من الإجمالي</span>
                </div>
              </div>

              {/* Filters */}
              <div className="expenses-filters-row">
                <div className="expenses-search">
                  <span className="material-symbols-outlined">search</span>
                  <input
                    type="text"
                    placeholder="بتدور على إيه؟"
                    value={searchTerm}
                    onChange={(e) => {
                      setSearchTerm(e.target.value);
                      setCurrentPage(1);
                    }}
                  />
                </div>
                <div className="expenses-category-tabs">
                  {['all', 'labor', 'chemicals', 'irrigation', 'fuel', 'other'].map((cat) => (
                    <button
                      key={cat}
                      className={`tab-chip ${categoryFilter === cat ? 'active' : ''}`}
                      onClick={() => {
                        setCategoryFilter(cat);
                        setCurrentPage(1);
                      }}
                    >
                      {cat === 'all' ? 'الكل' :
                        cat === 'labor' ? 'عمالة' :
                          cat === 'chemicals' ? 'كيماويات' :
                            cat === 'irrigation' ? 'رش' :
                              cat === 'fuel' ? 'وقود' :
                                'أخرى'}
                    </button>
                  ))}
                </div>
              </div>

              {/* Table */}
              <div className="expenses-table-card exp-card">
                <table className="expenses-table">
                  <thead>
                    <tr>
                      <th>الفئة</th>
                      <th>التاريخ</th>
                      <th>الوصف</th>
                      <th>المبلغ</th>
                      <th>الاجراءات</th>
                    </tr>
                  </thead>
                  <tbody>
                    {pagedExpenses.map((exp) => (
                      // استخدمنا id-category كـ key لضمان عدم التكرار
                      <tr key={exp.unique_id}>
                        <td>
                          <span className={`category-pill cat-${exp.category}`}>
                            {exp.category === 'labor' ? 'عمالة' :
                              exp.category === 'chemicals' ? 'كيماويات' :
                                exp.category === 'irrigation' ? 'رش' : // دورات الرش هتظهر هنا
                                  exp.category === 'fuel' ? 'وقود' : 'أخرى'}
                          </span>
                        </td>
                        {/* تأكد من تحويل التاريخ لشكل مقروء */}
                        <td>{exp.date ? new Date(exp.date).toLocaleDateString('ar-EG') : '-'}</td>
                        <td>{exp.description}</td>
                        {/* تأكد من تحويل المبلغ لرقم قبل العرض */}
                        <td>{(Number(exp.amount) || 0).toLocaleString('ar-EG')} ج.م</td>
                        <td>
                          <div className="exp-row-actions">
                            {/* تأكدنا هنا إن القيمة true بالظبط، أي قيمة تانية (false أو undefined) هتظهر "تلقائي" */}
                            {exp.is_manual === true ? (
                              <>
                                <button
                                  className="icon-btn danger"
                                  onClick={() => handleDeleteExpense(exp)}
                                  title="حذف"
                                >
                                  <span className="material-symbols-outlined">delete</span>
                                </button>
                                <button
                                  className="icon-btn"
                                  onClick={() => handleEditExpense(exp)}
                                  title="تعديل"
                                >
                                  <span className="material-symbols-outlined">edit</span>
                                </button>
                              </>
                            ) : (
                              <span className="auto-badge">تلقائي</span>
                            )}
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>

                <div className="expenses-table-footer">
                  <span>
                    عرض {pagedExpenses.length} من أصل {filteredExpenses.length} مصروف
                  </span>
                  <div className="pagination">
                    <button
                      className={`page-btn ${currentPage === 1 ? 'disabled' : ''}`}
                      onClick={() => currentPage > 1 && setCurrentPage(currentPage - 1)}
                    >
                      {'<'}
                    </button>
                    {Array.from({ length: totalPages }).map((_, index) => {
                      const page = index + 1;
                      return (
                        <button
                          key={page}
                          className={`page-btn ${currentPage === page ? 'active' : ''}`}
                          onClick={() => setCurrentPage(page)}
                        >
                          {page}
                        </button>
                      );
                    })}
                    <button
                      className={`page-btn ${currentPage === totalPages ? 'disabled' : ''}`}
                      onClick={() => currentPage < totalPages && setCurrentPage(currentPage + 1)}
                    >
                      {'>'}
                    </button>
                  </div>
                </div>
              </div>
            </>
          )}
        </>
      )}

      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف المصروف"
        message="هل أنت متأكد أنك تريد حذف هذا المصروف؟"
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={handleCancelDelete}
      />
    </div>
  );
}

export default Expenses;