import React, { useMemo, useState, useEffect } from 'react';
import './SprayCycles.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';
import { sprayCyclesService } from '../../services/sprayCycles';

function SprayCycles() {
  const [cycles, setCycles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedId, setSelectedId] = useState(null);
  const [mode, setMode] = useState('list');
  const [editingCycle, setEditingCycle] = useState(null);
  const [confirmState, setConfirmState] = useState({ open: false, target: null });

  // --- حالات الترقيم (Pagination States) ---
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6;

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      setLoading(true);
      const data = await sprayCyclesService.getAll();
      setCycles(data);
      if (data.length > 0 && !selectedId) {
        setSelectedId(data[0].id);
      }
    } catch (err) {
      console.error("Error loading data:", err);
    } finally {
      setLoading(false);
    }
  };

  const totalPages = Math.ceil(cycles.length / itemsPerPage);
  const pagedCycles = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage;
    return cycles.slice(startIndex, startIndex + itemsPerPage);
  }, [cycles, currentPage]);

  const selectedCycle = useMemo(
    () => cycles.find((c) => c.id === selectedId) || cycles[0],
    [cycles, selectedId]
  );

  const monthlyTotal = useMemo(
    () => cycles.reduce((sum, c) => sum + (Number(c.total_cost) || 0), 0),
    [cycles]
  );

  // --- Handlers ---
  const handleAddCycle = () => {
    setEditingCycle({
      id: null,
      name: '',
      date: new Date().toISOString().split('T')[0],
      material: '',
      dose_per_feddan: '',
      weight: '', // إضافة حقل الوزن هنا
      total_cost: '',
      target_area: '',
      notes: '',
    });
    setMode('form');
  };

  const handleEditCycle = (cycleId) => {
    const cycle = cycles.find((c) => c.id === cycleId);
    if (!cycle) return;
    setEditingCycle({ ...cycle });
    setMode('form');
  };

  const handleDeleteCycle = (cycleId) => {
    const cycle = cycles.find((c) => c.id === cycleId);
    if (!cycle) return;
    setConfirmState({ open: true, target: cycle });
  };

  const handleConfirmDelete = async () => {
    const target = confirmState.target;
    if (!target) return;
    try {
      await sprayCyclesService.delete(target.id);
      const updatedList = cycles.filter(c => c.id !== target.id);
      setCycles(updatedList);
      if (selectedId === target.id && updatedList.length > 0) {
        setSelectedId(updatedList[0].id);
      }
      if (pagedCycles.length === 1 && currentPage > 1) {
        setCurrentPage(prev => prev - 1);
      }
    } catch (err) {
      alert("فشل الحذف من السيرفر");
    }
    setConfirmState({ open: false, target: null });
  };

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    try {
      const payload = { ...editingCycle };
      delete payload.id;

      if (editingCycle.id === null) {
        const newRecord = await sprayCyclesService.create(payload);
        setCycles([newRecord, ...cycles]);
        setSelectedId(newRecord.id);
        setCurrentPage(1);
      } else {
        const updatedRecord = await sprayCyclesService.update(editingCycle.id, payload);
        setCycles(cycles.map(c => c.id === editingCycle.id ? updatedRecord : c));
        setSelectedId(updatedRecord.id);
      }
      setMode('list');
      setEditingCycle(null);
    } catch (err) {
      alert("حدث خطأ أثناء حفظ البيانات");
    }
  };

  const handleFormChange = (field, value) => {
    setEditingCycle(prev => ({ ...prev, [field]: value }));
  };

  if (loading && cycles.length === 0) {
    return <div style={{ padding: '50px', textAlign: 'center' }}>جاري تحميل البيانات من السيرفر...</div>;
  }

  return (
    <div className="spray-cycles-page">
      <div className="spray-cycles-header">
        <div>
          <h1>دورات الرش</h1>
          <p className="spray-cycles-subtitle">متابعة حية للبيانات لتفاصيل الرش</p>
        </div>
        {mode === 'list' && (
          <button className="btn-add-cycle" onClick={handleAddCycle}>
            <span className="material-symbols-outlined">add</span>
            إضافة دورة جديدة
          </button>
        )}
      </div>

      <div className="spray-cycles-layout">
        <div className="spray-cycles-list-card">
          <div className="spray-cycles-list-header">
            <span>اسم الدورة</span>
            <span>التاريخ</span>
            <span>المكان</span>
            <span>الوزن</span> {/* عمود الوزن الجديد */}
            <span>الكمية</span>
            <span>التكلفة</span>
            <span>إجراءات</span>
          </div>

          <div className="spray-cycles-list-body">
            {pagedCycles.map((cycle) => (
              <button
                key={cycle.id}
                className={`spray-cycle-row${cycle.id === selectedId ? ' active' : ''}`}
                onClick={() => setSelectedId(cycle.id)}
              >
                <span className="cycle-name">{cycle.name}</span>
                <span className="cycle-date">{cycle.date}</span>
                <span className="cycle-area">{cycle.target_area || '-'}</span>
                <span className="cycle-weight">{cycle.weight || '0'} كجم</span> {/* عرض الوزن */}
                <span className="cycle-dose">{cycle.dose_per_feddan || '-'}</span>
                <span className="cycle-cost">{Number(cycle.total_cost).toLocaleString()} ج.م</span>
                <span className="cycle-actions">
                  <span className="icon-btn danger" onClick={(e) => { e.stopPropagation(); handleDeleteCycle(cycle.id); }}>
                    <span className="material-symbols-outlined">delete</span>
                  </span>
                  <span className="icon-btn" onClick={(e) => { e.stopPropagation(); handleEditCycle(cycle.id); }}>
                    <span className="material-symbols-outlined">edit</span>
                  </span>
                </span>
              </button>
            ))}
          </div>

          {cycles.length > 0 && (
            <div className="labor-table-footer">
              <span>عرض {pagedCycles.length} من أصل {cycles.length} دورة</span>
              <div className="pagination">
                <button
                  className={`page-btn ${currentPage === 1 ? 'disabled' : ''}`}
                  onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                  disabled={currentPage === 1}
                >
                  <span className="material-symbols-outlined">chevron_right</span>
                </button>

                {Array.from({ length: totalPages }).map((_, i) => {
                  const page = i + 1;
                  return (
                    <button
                      key={page}
                      className={`page-btn ${currentPage === page ? 'active' : ''}`}
                      onClick={() => setCurrentPage(page)}
                    >
                      {page}
                    </button>
                  );
                })}

                <button
                  className={`page-btn ${currentPage === totalPages ? 'disabled' : ''}`}
                  onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                  disabled={currentPage === totalPages}
                >
                  <span className="material-symbols-outlined">chevron_left</span>
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="spray-cycles-detail-column">
          <div className="spray-cycles-summary-card">
            <div className="summary-icon"><span className="material-symbols-outlined">payments</span></div>
            <div className="summary-content">
              <span className="summary-label">إجمالي التكاليف المسجلة</span>
              <span className="summary-value">{monthlyTotal.toLocaleString()} ج.م</span>
            </div>
          </div>

          {mode === 'form' ? (
            <div className="spray-cycle-detail-card">
              <h2 className="detail-title">{editingCycle.id ? 'تعديل البيانات' : 'دورة جديدة'}</h2>
              <form className="spray-form" onSubmit={handleFormSubmit}>
                <div className="detail-grid">
                  <div className="detail-item">
                    <span className="detail-label">اسم الدورة</span>
                    <input type="text" value={editingCycle.name} onChange={(e) => handleFormChange('name', e.target.value)} required />
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">التاريخ</span>
                    <input type="date" value={editingCycle.date} onChange={(e) => handleFormChange('date', e.target.value)} />
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">المكان</span>
                    <input type="text" value={editingCycle.target_area} onChange={(e) => handleFormChange('target_area', e.target.value)} />
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">الوزن (كجم)</span> {/* حقل إدخال الوزن الجديد */}
                    <input type="number" step="0.01" value={editingCycle.weight} onChange={(e) => handleFormChange('weight', e.target.value)} />
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">الكمية</span>
                    <input type="text" value={editingCycle.dose_per_feddan} onChange={(e) => handleFormChange('dose_per_feddan', e.target.value)} />
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">المادة</span>
                    <input type="text" value={editingCycle.material} onChange={(e) => handleFormChange('material', e.target.value)} />
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">التكلفة</span>
                    <input type="number" value={editingCycle.total_cost} onChange={(e) => handleFormChange('total_cost', e.target.value)} />
                  </div>
                </div>
                <div className="detail-notes">
                  <span className="detail-label">الملاحظات</span>
                  <textarea value={editingCycle.notes} onChange={(e) => handleFormChange('notes', e.target.value)} />
                </div>
                <div className="detail-actions">
                  <button type="button" className="btn-secondary" onClick={() => setMode('list')}>إلغاء</button>
                  <button type="submit" className="btn-add-cycle">حفظ التغييرات</button>
                </div>
              </form>
            </div>
          ) : (
            selectedCycle && (
              <div className="spray-cycle-detail-card">
                <div className="detail-header-row">
                  <div>
                    <span className="detail-label">تفاصيل الدورة المختارة</span>
                    <h2 className="detail-title">{selectedCycle.name}</h2>
                  </div>
                </div>
                <div className="detail-grid">
                  <div className="detail-item">
                    <span className="detail-label">التاريخ</span>
                    <span className="detail-value">{selectedCycle.date}</span>
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">المكان</span>
                    <span className="detail-value">{selectedCycle.target_area || 'غير محدد'}</span>
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">الوزن</span>
                    <span className="detail-value">{selectedCycle.weight || '0'} كجم</span>
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">الكمية</span>
                    <span className="detail-value">{selectedCycle.dose_per_feddan || '-'}</span>
                  </div>
                  <div className="detail-item">
                    <span className="detail-label">المادة المستخدمة</span>
                    <span className="detail-value">{selectedCycle.material}</span>
                  </div>
                </div>
                <div className="detail-notes">
                  <span className="detail-label">الملاحظات</span>
                  <p>{selectedCycle.notes || 'لا توجد ملاحظات إضافية'}</p>
                </div>
                <div className="detail-actions">
                  <button className="btn-secondary" onClick={() => handleEditCycle(selectedCycle.id)}>تعديل</button>
                </div>
              </div>
            )
          )}
        </div>
      </div>

      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد الحذف النهائي"
        message={`سيتم حذف "${confirmState.target?.name}" من قاعدة البيانات بشكل دائم.`}
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmState({ open: false, target: null })}
      />
    </div>
  );
}

export default SprayCycles;