import React, { useState, useEffect } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';

// Layouts & Components
import LandingLayout from './layouts/LandingLayout';
import DashboardLayout from './layouts/DashboardLayout';
import ProtectedRoute from './components/common/ProtectedRoute';

// Landing Pages
import Home from './pages/landing/Home';
import Features from './pages/landing/Features';
import About from './pages/landing/About';
import Contact from './pages/landing/Contact';
import Pricing from './pages/landing/Pricing';

// Auth Pages
import Login from './pages/auth/Login';
import Register from './pages/auth/Register';

// Dashboard Pages
import Overview from './pages/dashboard/Overview';
import Expenses from './pages/dashboard/Expenses';
import Labor from './pages/dashboard/Labor';
import Chemicals from './pages/dashboard/Chemicals';
import SprayCycles from './pages/dashboard/SprayCycles';
import Irrigation from './pages/dashboard/Irrigation';
import Notifications from './pages/dashboard/Notifications';
import Account from './pages/dashboard/Account';
import Settings from './pages/dashboard/Settings';
import Reports from './pages/dashboard/Reports';

// Services
import { onAuthStateChange } from './services/auth';

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChange((authUser) => {
      setUser(authUser);
      setLoading(false);
    });

    return () => {
      if (unsubscribe) unsubscribe();
    };
  }, []);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', direction: 'rtl' }}>
        <h2>جاري التحميل...</h2>
      </div>
    );
  }

  return (
    <Routes>
      {/* Landing Pages */}
      <Route element={<LandingLayout user={user} />}>
        <Route path="/" element={<Home />} />
        <Route path="/features" element={<Features />} />
        <Route path="/about" element={<About />} />
        <Route path="/contact" element={<Contact />} />
        <Route path="/pricing" element={<Pricing />} />
      </Route>

      {/* Auth Pages */}
      <Route path="/login" element={user ? <Navigate to="/dashboard" replace /> : <Login />} />
      <Route path="/register" element={user ? <Navigate to="/dashboard" replace /> : <Register />} />

      {/* Dashboard Pages */}
      <Route
        path="/dashboard"
        element={
          <ProtectedRoute user={user}>
            <DashboardLayout user={user} />
          </ProtectedRoute>
        }
      >
        <Route index element={<Overview />} />
        <Route path="expenses" element={<Expenses />} />
        <Route path="labor" element={<Labor />} />
        <Route path="chemicals" element={<Chemicals />} />
        <Route path="spray-cycles" element={<SprayCycles />} />
        <Route path="irrigation" element={<Irrigation />} />
        <Route path="reports" element={<Reports />} />
        <Route path="notifications" element={<Notifications />} />
        <Route path="account" element={<Account />} />
        <Route path="settings" element={<Settings />} />
      </Route>
      
      {/* تحويل أي رابط غلط للرئيسية */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
}

export default App;