import React, { useState } from 'react';
import { Outlet } from 'react-router-dom';
import Sidebar from '../components/dashboard/Sidebar';
import TopBar from '../components/dashboard/TopBar';
import './DashboardLayout.css';

function DashboardLayout() {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <div className="dashboard-layout">
      {sidebarOpen && <div className="sidebar-backdrop" onClick={toggleSidebar}></div>}
      <Sidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} />
      <div className="dashboard-main">
        <TopBar onMenuClick={toggleSidebar} />
        <div className="dashboard-content">
          <Outlet />
          <p className="dashboard-footer">
            حالياً في مرحلة التطوير، ترقبوا المزيد من الميزات قريباً!
            <br />
            © 2026 <strong>ديوان الأرض</strong>. كل الحقوق محفوظة.
            <br />
            برمجة وتصميم: <strong>محمد سلامة</strong> |
            فكرة ومحتوى ومسؤول عن التطوير والإدارة الرقمية: <strong>عبدالله جابر</strong> و <strong>محمد سلامة</strong>
          </p>

        </div>
      </div>

    </div>
  );
}

export default DashboardLayout;
