import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { signUp } from '../../services/auth';
import './Auth.css';

function Register() {
  const navigate = useNavigate();
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [role, setRole] = useState('owner');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // التحقق من صحة البيانات
    if (!firstName || !lastName || !email || !password || !confirmPassword) {
      setError('يرجى ملء جميع الحقول');
      setLoading(false);
      return;
    }

    if (password !== confirmPassword) {
      setError('كلمات المرور غير متطابقة');
      setLoading(false);
      return;
    }

    if (password.length < 6) {
      setError('يجب أن تكون كلمة المرور 6 أحرف على الأقل');
      setLoading(false);
      return;
    }

    // استدعاء Supabase SignUp
    const fullName = `${firstName} ${lastName}`;
    const result = await signUp(email, password, fullName, role);
     if (result.success) {
      navigate('/login', { state: { message: 'تم إنشاء الحساب بنجاح! يرجى تسجيل الدخول' } });
    } else {
      setError(result.error || 'خطأ في إنشاء الحساب');
    }

    setLoading(false);
  };

  return (
    <div className="auth-page">
      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <Link to="/" className="auth-logo">
              ديوان <span className="logo-accent">الأرض</span>
            </Link>
            <h2>إنشاء حساب جديد</h2>
            <p>ابدأ رحلة التحول الرقمي لمزرعتك اليوم</p>
          </div>

          <form className="auth-form" onSubmit={handleSubmit}>
            <div className="form-row">
              <div className="form-group">
                <label>الاسم الأول</label>
                <div className="input-icon-group">
                  <span className="material-symbols-outlined">person</span>
                  <input
                    type="text"
                    placeholder="أحمد"
                    value={firstName}
                    onChange={(e) => setFirstName(e.target.value)}
                    disabled={loading}
                  />
                </div>
              </div>
              <div className="form-group">
                <label>اسم العائلة</label>
                <div className="input-icon-group">
                  <span className="material-symbols-outlined">person</span>
                  <input
                    type="text"
                    placeholder="محمد"
                    value={lastName}
                    onChange={(e) => setLastName(e.target.value)}
                    disabled={loading}
                  />
                </div>
              </div>
            </div>

            <div className="form-group">
              <label>نوع الحساب</label>
              <div className="user-type-group">
                <label>
                  <input
                    type="radio"
                    name="userType"
                    value="owner"
                    checked={role === 'owner'}
                    onChange={(e) => setRole(e.target.value)}
                    disabled={loading}
                  />
                  صاحب أرض
                </label>
                <label>
                  <input
                    type="radio"
                    name="userType"
                    value="partner"
                    checked={role === 'partner'}
                    onChange={(e) => setRole(e.target.value)}
                    disabled={loading}
                  />
                  تابع لصاحب أرض
                </label>
                <label>
                  <input
                    type="radio"
                    name="userType"
                    value="engineer"
                    checked={role === 'engineer'}
                    onChange={(e) => setRole(e.target.value)}
                    disabled={loading}
                  />
                  مهندس زراعي
                </label>
                <label>
                  <input
                    type="radio"
                    name="userType"
                    value="manager"
                    checked={role === 'manager'}
                    onChange={(e) => setRole(e.target.value)}
                    disabled={loading}
                  />
                  مسؤول عن أرض
                </label>
              </div>
            </div>

            <div className="form-group">
              <label>البريد الإلكتروني</label>
              <div className="input-icon-group">
                <span className="material-symbols-outlined">mail</span>
                <input
                  type="email"
                  placeholder="email@example.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  disabled={loading}
                />
              </div>
            </div>

            <div className="form-group">
              <label>كلمة المرور</label>
              <div className="input-icon-group">
                <span className="material-symbols-outlined">lock</span>
                <input
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={loading}
                />
              </div>
            </div>

            <div className="form-group">
              <label>تأكيد كلمة المرور</label>
              <div className="input-icon-group">
                <span className="material-symbols-outlined">lock_reset</span>
                <input
                  type="password"
                  placeholder="••••••••"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  disabled={loading}
                />
              </div>
            </div>

            {error && <div style={{ color: 'red', marginBottom: '10px' }}>{error}</div>}

            <button type="submit" className="btn-primary-custom btn-full" disabled={loading}>
              {loading ? 'جاري المعالجة...' : 'إنشاء الحساب'}
            </button>
          </form>

          <div className="auth-footer">
            <p>لديك حساب بالفعل؟ <Link to="/login">تسجيل الدخول</Link></p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
