import { supabase } from './supabase';

export const fetchOverviewData = async () => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  // سحب البيانات من الـ 6 جداول في وقت واحد
  const [expenses, income, labor, spray, chemicals, irrigation] = await Promise.all([
    supabase.from('expenses').select('*').eq('user_id', user.id),
    supabase.from('income').select('*').eq('user_id', user.id),
    supabase.from('labor').select('*').eq('user_id', user.id),
    supabase.from('spray_cycles').select('*').eq('user_id', user.id),
    supabase.from('chemicals').select('*').eq('user_id', user.id),
    supabase.from('irrigation').select('*').eq('user_id', user.id)
  ]);

  // تجهيز مصفوفة النشاطات الكبرى
  const allActivities = [
    ...(expenses.data || []).map(i => ({ ...i, type: 'expense', title: i.description, amount: i.amount, category: i.category })),
    ...(income.data || []).map(i => ({ ...i, type: 'income', title: i.source, amount: i.amount, category: 'دخل' })),
    ...(labor.data || []).map(i => ({ ...i, type: 'labor', title: `يومية: ${i.worker_name}`, amount: i.amount, category: i.task_type })),
    ...(spray.data || []).map(i => ({ ...i, type: 'spray', title: i.name, amount: i.total_cost, category: 'رش' })),
    ...(chemicals.data || []).map(i => ({ ...i, type: 'chemical', title: i.name, amount: i.cost, category: 'شراء مواد' })),
    ...(irrigation.data || []).map(i => ({ ...i, type: 'irrigation', title: `ري ${i.block || ''}`, amount: 0, category: i.status }))
  ].sort((a, b) => new Date(b.date || b.created_at) - new Date(a.date || a.created_at));

  // حساب الإحصائيات (Stats)
  const totalExp = (expenses.data?.reduce((sum, i) => sum + Number(i.amount), 0) || 0) +
                   (labor.data?.reduce((sum, i) => sum + Number(i.amount), 0) || 0) +
                   (spray.data?.reduce((sum, i) => sum + Number(i.total_cost), 0) || 0) +
                   (chemicals.data?.reduce((sum, i) => sum + Number(i.cost), 0) || 0);

  const totalInc = income.data?.reduce((sum, i) => sum + Number(i.amount), 0) || 0;

  return {
    stats: {
      totalExpenses: totalExp,
      totalIncome: totalInc,
      profit: totalInc - totalExp,
      laborCount: labor.data?.length || 0,
      sprayCount: spray.data?.length || 0
    },
    breakdown: {
      labor: labor.data?.reduce((sum, i) => sum + Number(i.amount || 0), 0) || 0,
      chemicals: chemicals.data?.reduce((sum, i) => sum + Number(i.cost || 0), 0) || 0,
      spray: spray.data?.reduce((sum, i) => sum + Number(i.total_cost || 0), 0) || 0
    },
    activities: allActivities
  };
};