import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { signOut } from '../../services/auth';
import ConfirmDialog from '../common/ConfirmDialog'; // تأكد من صحة المسار للمكون بتاعك
import './TopBar.css';

function TopBar({ onMenuClick }) {
  const location = useLocation();
  const navigate = useNavigate();

  // الحالة الخاصة بنافذة تأكيد الخروج
  const [isLogoutDialogOpen, setIsLogoutDialogOpen] = useState(false);

  const getPageTitle = () => {
    const path = location.pathname;
    if (path === '/dashboard') return 'التقرير الجامع';
    if (path === '/dashboard/reports') return 'التقارير التحليلية';
    if (path === '/dashboard/expenses') return 'إدارة المصاريف';
    if (path === '/dashboard/labor') return 'إدارة العمالة';
    if (path === '/dashboard/chemicals') return 'إدارة الكيماويات';
    if (path === '/dashboard/spray-cycles') return 'دورات الرش';
    if (path === '/dashboard/notifications') return 'الإشعارات';
    if (path === '/dashboard/account') return 'حسابي';
    return 'التقرير الجامع';
  };

  // عند الضغط على زر "خروج"
  const handleLogoutClick = () => {
    setIsLogoutDialogOpen(true);
  };

  // تنفيذ تسجيل الخروج الفعلي بعد التأكيد
  const handleConfirmLogout = async () => {
    setIsLogoutDialogOpen(false);
    const result = await signOut();
    if (result.success) {
      navigate('/login', { replace: true });
    } else {
      console.error('Logout failed');
    }
  };

  return (
    <>
      <header className="dashboard-topbar">
        <div className="topbar-left">
          <button className="menu-btn" onClick={onMenuClick} aria-label="فتح القائمة">
            <span className="material-symbols-outlined">menu</span>
          </button>
        </div>

        <div className="topbar-right">
          <h1 className="page-title">{getPageTitle()} | <span className="beta-label">نسخة تجريبية</span></h1>
        </div>

        <div className="topbar-actions">
          {/* زر تسجيل الخروج - اللون الأحمر واللوجو */}
          <div
            className="topbar-icon-btn logout-btn"
            role="button"
            tabIndex={0}
            onClick={handleLogoutClick}
          >
            <span className="material-symbols-outlined">logout</span>
            <span className="topbar-icon-label">خروج</span>
          </div>

          {/* زر الإشعارات */}
          <div
            className={`topbar-icon-btn ${location.pathname === '/dashboard/notifications' ? 'active' : ''}`}
            onClick={() => navigate('/dashboard/notifications')}
          >
            <span className="material-symbols-outlined">notifications</span>
            <span className="notification-dot"></span>
            <span className="topbar-icon-label">الإشعارات</span>
          </div>

          {/* زر الحساب */}
          <div
            className={`topbar-user ${location.pathname === '/dashboard/account' ? 'active' : ''}`}
            onClick={() => navigate('/dashboard/account')}
          >
            <img
              src="https://api.dicebear.com/7.x/avataaars/svg?seed=mohamed"
              alt="User"
              className="topbar-avatar"
            />
            <span className="topbar-icon-label">حسابي</span>
          </div>
        </div>
      </header>

      {/* استدعاء مكون التأكيد الخاص بك */}
      <ConfirmDialog
        open={isLogoutDialogOpen}
        title="تأكيد تسجيل الخروج"
        message="هل أنت متأكد أنك تريد الخروج من النظام؟"
        confirmLabel="تسجيل خروج"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmLogout}
        onCancel={() => setIsLogoutDialogOpen(false)}
      />
    </>
  );
}

export default TopBar;