import React, { useEffect, useState } from 'react';
import { NavLink, Link, useNavigate, useLocation } from 'react-router-dom';
import { supabase } from '../../services/supabase';
import './Sidebar.css';

function Sidebar({ isOpen, onClose }) {
  const navigate = useNavigate();
  const location = useLocation();
  const [user, setUser] = useState({ name: '', role: '' });

  // دالة موحدة لتحويل الكود النصي للدور إلى اسم عربي
  const getRoleName = (role) => {
    const roles = {
      'owner': 'صاحب أرض',
      'partner': 'تابع لصاحب أرض',
      'engineer': 'مهندس زراعي',
      'manager': 'مسؤول عن أرض'
    };
    return roles[role] || '---';
  };

  useEffect(() => {
    const fetchUser = async () => {
      // 1. الحصول على المستخدم الحالي من الـ Session
      const { data: { user: authUser }, error: authError } = await supabase.auth.getUser();

      if (authError || !authUser) return;

      // 2. جلب البيانات من جدول الـ public.users باستخدام الـ ID
      const { data: profile, error: dbError } = await supabase
        .from('users')
        .select('full_name, role')
        .eq('id', authUser.id)
        .single();

      if (dbError) {
        console.error("Error fetching profile from table:", dbError);
        // fallback: إذا فشل الجدول، اعرض بيانات الميتاداتا مؤقتاً
        setUser({
          name: authUser.user_metadata?.full_name || '---',
          role: getRoleName(authUser.user_metadata?.role),
        });
        return;
      }

      // 3. تحديث الحالة ببيانات الجدول
      if (profile) {
        setUser({
          name: profile.full_name,
          role: getRoleName(profile.role),
        });
      }
    };

    fetchUser();
    // ... باقي كود الـ Listener
  }, []);

  const menuItems = [
    { name: 'التقرير الجامع', path: '/dashboard', icon: 'grid_view', end: true },
    { name: 'المصاريف', path: '/dashboard/expenses', icon: 'payments' },
    { name: 'العمالة', path: '/dashboard/labor', icon: 'groups' },
    { name: 'الكيماويات', path: '/dashboard/chemicals', icon: 'experiment' },
    { name: 'دورات الرش', path: '/dashboard/spray-cycles', icon: 'event_available' },
    { name: 'الري', path: '/dashboard/irrigation', icon: 'water_drop' },
    { name: 'التقارير', path: '/dashboard/reports', icon: 'bar_chart' },
  ];

  return (
    <aside className={`dashboard-sidebar ${isOpen ? 'open' : ''}`}>
      <div className="sidebar-header">
        <Link to="/" className="sidebar-logo">
          <img src="/img/logo.jpeg" alt="Logo" className="logo-img" />
          <div className="logo-info">
            <span className="logo-name">ديوان الأرض</span>
            <span className="logo-desc">إدارة مزارع ذكية</span>
          </div>
        </Link>
      </div>

      <nav className="sidebar-nav">

        <ul>

          {menuItems.map((item, index) => (
            <li key={index}>
              <NavLink
                to={item.path}
                end={item.end}
                className={({ isActive }) => isActive ? "sidebar-link active" : "sidebar-link"}
                onClick={onClose}
              >
                <span className="material-symbols-outlined">{item.icon}</span>
                <span>{item.name}</span>
              </NavLink>
            </li>
          ))}
        </ul>
      </nav>

      <div className="sidebar-footer">
        <NavLink to="/dashboard/settings" className="sidebar-link settings-link" onClick={onClose}>
          <span className="material-symbols-outlined">settings</span>
          <span>الإعدادات</span>
        </NavLink>

        <div
          className={`profile-card ${location.pathname === '/dashboard/account' ? 'active' : ''}`}
          role="button"
          tabIndex={0}
          onClick={() => { navigate('/dashboard/account'); onClose(); }}
        >
          <div className="profile-info">
            {/* تأكدنا هنا من عرض الاسم والدور بشكل صحيح */}
            <span className="user-name">{user.name}</span>
            <span className="user-role">{user.role}</span>
          </div>
          <div className="profile-avatar">
            <span className="material-symbols-outlined"> <img
              src="https://api.dicebear.com/7.x/avataaars/svg?seed=mohamed"
              alt="User"
              className="topbar-avatar"
              style={{ borderRadius: "50%" }}
            /></span>
            <span className="profile-icon-label">حسابي</span>
          </div>
        </div>
      </div>
    </aside>
  );
}

export default Sidebar;