import React, { useMemo, useState, useEffect } from 'react';
import { supabase } from '../../services/supabase';
import './Labor.css';
import '../../components/common/ConfirmDialog.css';
import ConfirmDialog from '../../components/common/ConfirmDialog';
import { addLaborLog, updateLaborLog, deleteLaborLog } from '../../services/labor';

function getInitials(name) {
  if (!name) return '';
  const parts = name.trim().split(' ');
  if (parts.length === 1) return parts[0][0] || '';
  return `${parts[0][0]}${parts[parts.length - 1][0]}`;
}

function Labor() {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [mode, setMode] = useState('list'); // 'list' | 'form'
  const [editingTask, setEditingTask] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [taskFilter, setTaskFilter] = useState('all');
  const [paymentFilter, setPaymentFilter] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 4;
  const [confirmState, setConfirmState] = useState({ open: false, target: null });
  

  // جلب البيانات عند البداية
  useEffect(() => {
    const fetchTasks = async () => {
      try {
        const { data, error } = await supabase.from('labor').select('*');
        if (error) throw error;

        const formatted = data.map(t => ({
          ...t,
          workerName: t.worker_name,
          taskType: t.task_type,
          taskTag: t.task_tag,
          paymentStatusType: t.payment_status_type || 'pending',
        }));

        setTasks(formatted);
      } catch (err) {
        console.error("Error loading tasks", err);
      } finally {
        setLoading(false);
      }
    };
    fetchTasks();
  }, []);

  const totalWorkersToday = tasks.length;
  const totalCompletedTasks = tasks.filter(t => t.paymentStatusType === 'paid').length;
  const pendingTasksCount = tasks.filter(t => t.paymentStatusType === 'pending').length;

  const totalAmount = useMemo(
    () => tasks.reduce((sum, t) => sum + (Number(t.amount) || 0), 0),
    [tasks]
  );

const filteredTasks = useMemo(() => {
  return tasks.filter(t => {
    const searchLower = searchTerm.toLowerCase();
    const taskDateStr = new Date(t.date).toISOString().slice(0,10); // YYYY-MM-DD
    const matchesSearch =
      !searchTerm ||
      (t.workerName && t.workerName.toLowerCase().includes(searchLower)) ||
      (t.taskType && t.taskType.toLowerCase().includes(searchLower)) ||
      (t.taskTag && t.taskTag.toLowerCase().includes(searchLower)) ||
      taskDateStr.includes(searchTerm); // إضافة التاريخ للبحث

    const matchesTask = taskFilter === 'all' || t.taskType === taskFilter;
    const matchesPayment = paymentFilter === 'all' || t.paymentStatusType === paymentFilter;

    return matchesSearch && matchesTask && matchesPayment;
  });
}, [tasks, searchTerm, taskFilter, paymentFilter]);

  const totalPages = Math.max(1, Math.ceil(filteredTasks.length / pageSize));

  const pagedTasks = useMemo(() => {
    const start = (currentPage - 1) * pageSize;
    return filteredTasks.slice(start, start + pageSize);
  }, [filteredTasks, currentPage]);

  const handleAddWorker = () => {
    setEditingTask({
      id: null,
      workerName: '',
      taskType: 'حصاد',
      taskTag: '',
      date: new Date().toISOString().slice(0, 10),
      amount: 0,
      paymentStatusType: 'pending',
    });
    setMode('form');
  };

  const handleEditTask = (task) => {
    setEditingTask({ ...task });
    setMode('form');
  };

  const handleDeleteTask = (task) => {
    setConfirmState({ open: true, target: task });
  };

  const handleConfirmDelete = async () => {
    const target = confirmState.target;
    if (!target) return;
    try {
      const result = await deleteLaborLog(target.id);
      if (result.success) {
        setTasks(tasks.filter(t => t.id !== target.id));
        setConfirmState({ open: false, target: null });
      } else {
        alert("خطأ في الحذف من السيرفر");
      }
    } catch (err) {
      alert("خطأ في الاتصال");
    }
  };

  const handleFormChange = (field, value) => {
    setEditingTask(prev => ({ ...prev, [field]: value }));
  };

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    if (!editingTask) return alert('لا يوجد بيانات لحفظها.');

    const taskData = {
      ...editingTask,
      paymentStatus: editingTask.paymentStatusType === 'paid' ? 'تم الدفع' : 'انتظار',
    };

    try {
      if (!editingTask.id) {
        const result = await addLaborLog(taskData);
        if (result.success) setTasks([result.data[0], ...tasks]);
        else throw new Error(result.error);
      } else {
        const result = await updateLaborLog(editingTask.id, taskData);
        if (result.success) setTasks(tasks.map(t => t.id === editingTask.id ? result.data[0] : t));
        else throw new Error(result.error);
      }
      setMode('list');
      setEditingTask(null);
    } catch (err) {
      alert(`حدث خطأ أثناء الحفظ: ${err.message}`);
    }
  };

  if (loading) return null;

  return (
    <div className="labor-page">
      <div className="labor-header-row">
        <button className="btn-primary large" onClick={handleAddWorker}>
          <span className="material-symbols-outlined">group_add</span>
          إضافة نفر جديد
        </button>
      </div>

      <div className="labor-main-card labor-card">
        {mode === 'form' && editingTask && (
          <div className="labor-form-card">
            <h2 className="form-title">
              {editingTask.id == null ? 'إضافة عامل / مهمة' : 'تعديل عامل / مهمة'}
            </h2>
            <form className="labor-form" onSubmit={handleFormSubmit}>
              <div className="form-row">
                <label>اسم العامل</label>
                <input
                  type="text"
                  value={editingTask.workerName}
                  onChange={e => handleFormChange('workerName', e.target.value)}
                  required
                />
              </div>
              <div className="form-row two-cols">
                <div>
                  <label>نوع المهمة</label>
                  <select
                    value={editingTask.taskType}
                    onChange={e => handleFormChange('taskType', e.target.value)}
                  >
                    <option value="حصاد">حصاد</option>
                    <option value="خدمة أرض">خدمة أرض</option>
                    <option value="تقليم">تقليم</option>
                    <option value="تحميل ونقل">تحميل ونقل</option>
                    <option value="ري ومتابعة">ري ومتابعة</option>
                  </select>
                </div>
                <div>
                  <label>الوصف المختصر للمهمة</label>
                  <input
                    type="text"
                    value={editingTask.taskTag}
                    onChange={e => handleFormChange('taskTag', e.target.value)}
                  />
                </div>
              </div>
              <div className="form-row two-cols">
                <div>
                  <label>التاريخ</label>
                  <input
                    type="date"
                    value={editingTask.date}
                    onChange={e => handleFormChange('date', e.target.value)}
                  />
                </div>
                <div>
                  <label>المبلغ المستحق (ج.م)</label>
                  <input
                    type="number"
                    value={editingTask.amount}
                    onChange={e => handleFormChange('amount', e.target.value)}
                    min="0"
                  />
                </div>
              </div>
              <div className="form-row">
                <label>حالة الدفع</label>
                <select
                  value={editingTask.paymentStatusType}
                  onChange={e => handleFormChange('paymentStatusType', e.target.value)}
                >
                  <option value="paid">تم الدفع</option>
                  <option value="pending">انتظار</option>
                  <option value="late">متأخر</option>
                </select>
              </div>
              <div className="form-actions">
                <button type="button" className="btn-secondary" onClick={() => setMode('list')}>إلغاء</button>
                <button type="submit" className="btn-primary">حفظ</button>
              </div>
            </form>
          </div>
        )}

        {/* الإحصائيات */}
        <div className="labor-stats-row">
          <div className="labor-stat-card">
            <span className="stat-label">المهام المكتملة</span>
            <span className="stat-value">{totalCompletedTasks}</span>
          </div>
          <div className="labor-stat-card">
            <span className="stat-label">إجمالي المستحقات</span>
            <span className="stat-value">{totalAmount.toLocaleString('ar-EG')} ج.م</span>
          </div>
          <div className="labor-stat-card">
            <span className="stat-label">المهام قيد التنفيذ</span>
            <span className="stat-value">{pendingTasksCount}</span>
          </div>
          <div className="labor-stat-card">
            <span className="stat-label">إجمالي العمال اليوم</span>
            <span className="stat-value">{totalWorkersToday}</span>
          </div>
        </div>

        {/* البحث والفلترة */}
        <div className="labor-filters-row">
          <div className="labor-search-inline">
            <span className="filter-label">بحث سريع</span>
            <div className="labor-search-wrapper small">
              <span className="material-symbols-outlined">search</span>
              <input
                type="text"
                placeholder="اسم العامل أو نوع المهمة..."
                value={searchTerm}
                onChange={e => { setSearchTerm(e.target.value); setCurrentPage(1); }}
              />
            </div>
          </div>

          <div className="labor-filters-chips">
            <span className="filter-label">فلترة حسب نوع المهمة</span>
            <div>
              {['all', 'حصاد', 'خدمة أرض', 'تقليم', 'تحميل ونقل', 'ري ومتابعة'].map(f => (
                <button
                  key={f}
                  className={`filter-chip ${taskFilter === f ? 'active' : ''}`}
                  onClick={() => { setTaskFilter(f); setCurrentPage(1); }}
                >
                  {f === 'all' ? 'الكل' : f}
                </button>
              ))}
            </div>
          </div>

          <div className="labor-filters-chips">
            <span className="filter-label">حالة الدفع</span>
            <div>
              {['all', 'paid', 'pending', 'late'].map(p => (
                <button
                  key={p}
                  className={`filter-chip ${paymentFilter === p ? 'active' : ''}`}
                  onClick={() => { setPaymentFilter(p); setCurrentPage(1); }}
                >
                  {p === 'all' ? 'الكل' : p === 'paid' ? 'تم الدفع' : p === 'pending' ? 'انتظار' : 'متأخر'}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* الجدول */}
        <div className="labor-table-wrapper">
          <table className="labor-table">
            <thead>
              <tr>
                <th>اسم العامل</th>
                <th>نوع المهمة</th>
                <th>وصف المهمة</th>
                <th>التاريخ</th>
                <th>المبلغ المستحق</th>
                <th>حالة الدفع</th>
                <th>الإجراءات</th>
              </tr>
            </thead>
            <tbody>
              {pagedTasks.map(task => (
                <tr key={task.id}>
                  <td>
                    <div className="worker-cell">
                      <div className="worker-avatar"><span>{getInitials(task.worker_name)}</span></div>
                      <span>{task.worker_name}</span>
                    </div>
                  </td>
                  <td><span className="task-pill">{task.task_type}</span></td>
                  <td><span className="task-pill">{task.task_tag}</span></td>
                  <td>{new Date(task.date).toLocaleDateString('ar-EG')}</td>
                  <td>{Number(task.amount).toLocaleString('ar-EG')} ج.م</td>
                  <td>
                    <span className={`payment-status-pill ${task.payment_status_type}`}>
                      {task.payment_status_type === 'paid' ? 'تم الدفع' : task.payment_status_type === 'pending' ? 'انتظار' : 'متأخر'}
                    </span>
                  </td>
                  <td>
                    <div className="labor-row-actions">
                      <button className="icon-btn danger" onClick={() => handleDeleteTask(task)}>
                        <span className="material-symbols-outlined">delete</span>
                      </button>
                      <button className="icon-btn" onClick={() => handleEditTask(task)}>
                        <span className="material-symbols-outlined">edit</span>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* الفوتر والصفحات */}
        <div className="labor-table-footer">
          <span>عرض {pagedTasks.length} من أصل {filteredTasks.length} عامل</span>
          <div className="pagination">
            <button
              className={`page-btn ${currentPage === 1 ? 'disabled' : ''}`}
              onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
              disabled={currentPage === 1}
            >
              <span className="material-symbols-outlined">chevron_right</span>
            </button>

            {Array.from({ length: totalPages }).map((_, i) => {
              const page = i + 1;
              return (
                <button
                  key={page}
                  className={`page-btn ${currentPage === page ? 'active' : ''}`}
                  onClick={() => setCurrentPage(page)}
                >
                  {page}
                </button>
              );
            })}

            <button
              className={`page-btn ${currentPage === totalPages ? 'disabled' : ''}`}
              onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
              disabled={currentPage === totalPages}
            >
              <span className="material-symbols-outlined">chevron_left</span>
            </button>
          </div>
        </div>
      </div>

      <ConfirmDialog
        open={confirmState.open}
        title="تأكيد حذف سجل العامل"
        message="هل أنت متأكد أنك تريد حذف هذا السجل؟"
        confirmLabel="حذف"
        cancelLabel="إلغاء"
        onConfirm={handleConfirmDelete}
        onCancel={() => setConfirmState({ open: false, target: null })}
      />
    </div>
  );
}

export default Labor;