import { supabase } from './supabase';

export const chemicalsService = {
    // جلب كل البيانات
    async getAll() {
        try {
            const { data, error } = await supabase
                .from('chemicals')
                .select('*')
                .order('purchase_date', { ascending: false });
            
            if (error) throw error;
            return { success: true, data };
        } catch (error) {
            return { success: false, error: error.message };
        }
    },

    // إضافة عملية شراء جديدة
    async add(chemicalData) {
        try {
            const { data, error } = await supabase
                .from('chemicals')
                .insert([chemicalData])
                .select();
            
            if (error) throw error;
            return { success: true, data: data[0] };
        } catch (error) {
            return { success: false, error: error.message };
        }
    },

    // تحديث بيانات
    async update(id, chemicalData) {
        try {
            const { data, error } = await supabase
                .from('chemicals')
                .update(chemicalData)
                .eq('id', id)
                .select();
            
            if (error) throw error;
            return { success: true, data: data[0] };
        } catch (error) {
            return { success: false, error: error.message };
        }
    },

    // حذف سجل
    async delete(id) {
        try {
            const { error } = await supabase
                .from('chemicals')
                .delete()
                .eq('id', id);
            
            if (error) throw error;
            return { success: true };
        } catch (error) {
            return { success: false, error: error.message };
        }
    }
};